pragma solidity ^0.8.0;  

import "./manager/WeightedBalancerPoolManager.sol";
import "./IVault.sol";
import "../../utils/Timed.sol";
import "../../refs/OracleRef.sol";
import "../IPCVSwapper.sol";




contract BalancerLBPSwapper is IPCVSwapper, OracleRef, Timed, WeightedBalancerPoolManager {
    using Decimal for Decimal.D256;


    event MinTokenSpentUpdate(uint256 oldMinTokenSpentBalance, uint256 newMinTokenSpentBalance);



    IWeightedPool public pool;


    IVault public vault;


    bytes32 public pid;


    uint256 private constant ONE_PERCENT = 0.01e18;
    uint256 private constant NINETY_NINE_PERCENT = 0.99e18;


    IAsset[] private assets;
    uint256[] private initialWeights;
    uint256[] private endWeights;




    address public override tokenSpent;


    address public override tokenReceived;


    address public override tokenReceivingAddress;


    uint256 public minTokenSpentBalance;

    struct OracleData {
        address _oracle;
        address _backupOracle;

        bool _invertOraclePrice;

        int256 _decimalsNormalizer;
    }


    constructor(
        address _core,
        OracleData memory oracleData,
        uint256 _frequency,
        address _tokenSpent,
        address _tokenReceived,
        address _tokenReceivingAddress,
        uint256 _minTokenSpentBalance
    ) 
        OracleRef(
            _core, 
            oracleData._oracle, 
            oracleData._backupOracle,
            oracleData._decimalsNormalizer,
            oracleData._invertOraclePrice
        )
        Timed(_frequency) 
        WeightedBalancerPoolManager()
    {
        _initTimed();


        tokenSpent = _tokenSpent;
        tokenReceived = _tokenReceived;

        _setReceivingAddress(_tokenReceivingAddress);
        _setMinTokenSpent(_minTokenSpentBalance);
    }



    function init(IWeightedPool _pool) external {
        require(address(pool) == address(0), "BalancerLBPSwapper: initialized");

        pool = _pool;
        IVault _vault = _pool.getVault();

        vault = _vault;


        require(_pool.getOwner() == address(this), "BalancerLBPSwapper: contract not pool owner");


        bytes32 _pid = _pool.getPoolId();
        pid = _pid;
        (IERC20[] memory tokens,,) = _vault.getPoolTokens(_pid);
        require(tokens.length == 2, "BalancerLBPSwapper: pool does not have 2 tokens");
        require(
            tokenSpent == address(tokens[0]) || 
            tokenSpent == address(tokens[1]), 
            "BalancerLBPSwapper: tokenSpent not in pool"
        );        
        require(
            tokenReceived == address(tokens[0]) || 
            tokenReceived == address(tokens[1]), 
            "BalancerLBPSwapper: tokenReceived not in pool"
        );


        assets = new IAsset[](2);
        assets[0] = IAsset(address(tokens[0]));
        assets[1] = IAsset(address(tokens[1]));

        bool tokenSpentAtIndex0 = tokenSpent == address(tokens[0]);
        initialWeights = new uint[](2);
        endWeights = new uint[](2);

        if (tokenSpentAtIndex0) {
            initialWeights[0] = NINETY_NINE_PERCENT;
            initialWeights[1] = ONE_PERCENT;

            endWeights[0] = ONE_PERCENT;
            endWeights[1] = NINETY_NINE_PERCENT;
        }  else {
            initialWeights[0] = ONE_PERCENT;
            initialWeights[1] = NINETY_NINE_PERCENT;

            endWeights[0] = NINETY_NINE_PERCENT;
            endWeights[1] = ONE_PERCENT;
        }


        _pool.approve(address(_vault), type(uint256).max);
        IERC20(tokenSpent).approve(address(_vault), type(uint256).max);
        IERC20(tokenReceived).approve(address(_vault), type(uint256).max);
    }



    function swap() external override afterTime whenNotPaused {
        (
            uint256 spentReserves, 
            uint256 receivedReserves, 
            uint256 lastChangeBlock
        ) = getReserves();


        require(lastChangeBlock < block.number, "BalancerLBPSwapper: pool changed this block");

        (
            uint256 bptTotal,
            uint256 bptBalance, 
            uint256 spentBalance, 
            uint256 receivedBalance
        ) = getPoolBalances(spentReserves, receivedReserves);


        if (bptTotal == 0) {
            _initializePool();
            return;
        }
        require(swapEndTime() < block.timestamp, "BalancerLBPSwapper: weight update in progress");


        if (bptBalance != 0) {
            IVault.ExitPoolRequest memory exitRequest;


            bytes memory userData = abi.encode(IWeightedPool.ExitKind.EXACT_BPT_IN_FOR_TOKENS_OUT, bptBalance);

            exitRequest.assets = assets;
            exitRequest.minAmountsOut = new uint256[](2); 
            exitRequest.userData = userData;
            exitRequest.toInternalBalance = false; 

            vault.exitPool(
                pid,
                address(this),
                payable(address(this)),
                exitRequest
            );
        }


        _updateWeightsGradually(
            pool,
            block.timestamp, 
            block.timestamp, 
            initialWeights
        );


        uint256 spentTokenBalance = IERC20(tokenSpent).balanceOf(address(this));
        if (spentTokenBalance > minTokenSpentBalance) {


            uint256[] memory amountsIn = _getTokensIn(spentTokenBalance);
            bytes memory userData = abi.encode(IWeightedPool.JoinKind.EXACT_TOKENS_IN_FOR_BPT_OUT, amountsIn, 0);

            IVault.JoinPoolRequest memory joinRequest;
            joinRequest.assets = assets;
            joinRequest.maxAmountsIn = amountsIn;
            joinRequest.userData = userData;
            joinRequest.fromInternalBalance = false; 

            vault.joinPool(
                pid,
                address(this),
                payable(address(this)),
                joinRequest
            );


            _updateWeightsGradually(
                pool,
                block.timestamp, 
                block.timestamp + duration, 
                endWeights
            );
            _initTimed(); 
        }

        IERC20(tokenReceived).transfer(tokenReceivingAddress, IERC20(tokenReceived).balanceOf(address(this)));
    }


    function swapEndTime() public view returns(uint256 endTime) { 
        (,endTime,) = pool.getGradualWeightUpdateParams();
    }


    function getReserves() public view returns(uint256 spentReserves, uint256 receivedReserves, uint256 lastChangeBlock) {
        (IERC20[] memory tokens, uint256[] memory balances, uint256 _lastChangeBlock ) = vault.getPoolTokens(pid);
        if (address(tokens[0]) == tokenSpent) {
            return (balances[0], balances[1], _lastChangeBlock);
        }
        return (balances[1], balances[0], _lastChangeBlock);
    }


    function getPoolBalances(uint256 spentReserves, uint256 receivedReserves) public view returns (
        uint256 bptTotal, 
        uint256 bptBalance, 
        uint256 spentBalance, 
        uint256 receivedBalance
    ) {
        bptTotal = pool.totalSupply();
        bptBalance = pool.balanceOf(address(this));

        if (bptTotal != 0) {
            spentBalance = spentReserves * bptBalance / bptTotal;
            receivedBalance = receivedReserves * bptBalance / bptTotal;
        }
    } 



    function setSwapFrequency(uint256 _frequency) external onlyGovernorOrAdmin {
       _setDuration(_frequency);
    }



    function setMinTokenSpent(uint256 newMinTokenSpentBalance) external onlyGovernorOrAdmin {
       _setMinTokenSpent(newMinTokenSpentBalance);
    }



    function setReceivingAddress(address newTokenReceivingAddress) external override onlyGovernorOrAdmin {
        _setReceivingAddress(newTokenReceivingAddress);
    }

    function _setReceivingAddress(address newTokenReceivingAddress) internal {
      require(newTokenReceivingAddress != address(0), "BalancerLBPSwapper: zero address");
      address oldTokenReceivingAddress = tokenReceivingAddress;
      tokenReceivingAddress = newTokenReceivingAddress;
      emit UpdateReceivingAddress(oldTokenReceivingAddress, newTokenReceivingAddress);
    }

    function _initializePool() internal {

        uint256 spentTokenBalance = IERC20(tokenSpent).balanceOf(address(this)); 
        require(spentTokenBalance >= minTokenSpentBalance, "BalancerLBPSwapper: not enough tokenSpent to init");

        uint256[] memory amountsIn = _getTokensIn(spentTokenBalance);
        bytes memory userData = abi.encode(IWeightedPool.JoinKind.INIT, amountsIn);

        IVault.JoinPoolRequest memory joinRequest;
        joinRequest.assets = assets;
        joinRequest.maxAmountsIn = amountsIn;
        joinRequest.userData = userData;
        joinRequest.fromInternalBalance = false;

        vault.joinPool(
            pid,
            address(this),
            payable(address(this)),
            joinRequest
        );


        _updateWeightsGradually(
            pool,
            block.timestamp, 
            block.timestamp + duration, 
            endWeights
        );
        _initTimed();
    }

    function _getTokensIn(uint256 spentTokenBalance) internal view returns(uint256[] memory amountsIn) {
        amountsIn = new uint256[](2);

        uint256 receivedTokenBalance = readOracle().mul(spentTokenBalance).mul(ONE_PERCENT).div(NINETY_NINE_PERCENT).asUint256();

        if (address(assets[0]) == tokenSpent) {
            amountsIn[0] = spentTokenBalance;
            amountsIn[1] = receivedTokenBalance;
        } else {
            amountsIn[0] = receivedTokenBalance;
            amountsIn[1] = spentTokenBalance;
        }
    }

    function _setMinTokenSpent(uint256 newMinTokenSpentBalance) internal {
      uint256 oldMinTokenSpentBalance = minTokenSpentBalance;
      minTokenSpentBalance = newMinTokenSpentBalance;
      emit MinTokenSpentUpdate(oldMinTokenSpentBalance, newMinTokenSpentBalance);
    }
}

pragma solidity 0.7.6;

import "@openzeppelin/contracts/math/Math.sol";
import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/math/SignedSafeMath.sol";
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts/drafts/ERC20Permit.sol";

import "@uniswap/v3-core/contracts/interfaces/callback/IUniswapV3MintCallback.sol";
import "@uniswap/v3-core/contracts/interfaces/callback/IUniswapV3SwapCallback.sol";
import "@uniswap/v3-core/contracts/interfaces/IUniswapV3Pool.sol";
import "@uniswap/v3-core/contracts/libraries/TickMath.sol";
import "@uniswap/v3-core/contracts/libraries/FullMath.sol";
import "@uniswap/v3-periphery/contracts/libraries/LiquidityAmounts.sol";

import "./interfaces/IVault.sol";
import "./interfaces/IUniversalVault.sol";





contract Hypervisor is IVault, IUniswapV3MintCallback, IUniswapV3SwapCallback, ERC20Permit {
    using SafeERC20 for IERC20;
    using SafeMath for uint256;
    using SignedSafeMath for int256;

    IUniswapV3Pool public pool;
    IERC20 public token0;
    IERC20 public token1;
    uint24 public fee;
    int24 public tickSpacing;

    int24 public baseLower;
    int24 public baseUpper;
    int24 public limitLower;
    int24 public limitUpper;

    address public owner;
    uint256 public deposit0Max;
    uint256 public deposit1Max;
    uint256 public maxTotalSupply;
    mapping(address => bool) public list; 
    bool public whitelisted; 
    bool public directDeposit; 

    uint256 public constant PRECISION = 1e36;



    constructor(
        address _pool,
        address _owner,
        string memory name,
        string memory symbol
    ) ERC20Permit(name) ERC20(name, symbol) {
        pool = IUniswapV3Pool(_pool);
        token0 = IERC20(pool.token0());
        token1 = IERC20(pool.token1());
        fee = pool.fee();
        tickSpacing = pool.tickSpacing();

        owner = _owner;

        maxTotalSupply = 0; 
        deposit0Max = uint256(-1);
        deposit1Max = uint256(-1);
        whitelisted = false;
    }







    function deposit(
        uint256 deposit0,
        uint256 deposit1,
        address to,
        address from
    ) external override returns (uint256 shares) {
        require(deposit0 > 0 || deposit1 > 0, "deposits must be nonzero");
        require(deposit0 <= deposit0Max && deposit1 <= deposit1Max, "deposits must be less than maximum amounts");
        require(to != address(0) && to != address(this), "to");
        require(!whitelisted || list[from], "must be on the list");


        (uint128 baseLiquidity,,) = _position(baseLower, baseUpper);
        if (baseLiquidity > 0) {
            pool.burn(baseLower, baseUpper, 0);
        }
        (uint128 limitLiquidity,,)  = _position(limitLower, limitUpper);
        if (limitLiquidity > 0) {
            pool.burn(limitLower, limitUpper, 0);
        }

        uint160 sqrtPrice = TickMath.getSqrtRatioAtTick(currentTick());
        uint256 price = FullMath.mulDiv(uint256(sqrtPrice).mul(uint256(sqrtPrice)), PRECISION, 2**(96 * 2));

        (uint256 pool0, uint256 pool1) = getTotalAmounts();

        uint256 deposit0PricedInToken1 = deposit0.mul(price).div(PRECISION);
        shares = deposit1.add(deposit0PricedInToken1);

        if (deposit0 > 0) {
          token0.safeTransferFrom(from, address(this), deposit0);
        }
        if (deposit1 > 0) {
          token1.safeTransferFrom(from, address(this), deposit1);
        }

        if (totalSupply() != 0) {
          uint256 pool0PricedInToken1 = pool0.mul(price).div(PRECISION);
          shares = shares.mul(totalSupply()).div(pool0PricedInToken1.add(pool1));
          if(directDeposit) {
            baseLiquidity = _liquidityForAmounts(
                baseLower,
                baseUpper,
                token0.balanceOf(address(this)),
                token1.balanceOf(address(this))
            );
            _mintLiquidity(baseLower, baseUpper, baseLiquidity, address(this));

            limitLiquidity = _liquidityForAmounts(
                limitLower,
                limitUpper,
                token0.balanceOf(address(this)),
                token1.balanceOf(address(this))
            );
            _mintLiquidity(limitLower, limitUpper, limitLiquidity, address(this));
          }
        }
        _mint(to, shares);
        emit Deposit(from, to, shares, deposit0, deposit1);

        require(maxTotalSupply == 0 || totalSupply() <= maxTotalSupply, "maxTotalSupply");
    }

    function pullLiquidity(
      uint256 shares
    ) external onlyOwner returns(
        uint256 base0,
        uint256 base1,
        uint256 limit0,
        uint256 limit1
      ) {

        (uint256 base0, uint256 base1) = _burnLiquidity(
            baseLower,
            baseUpper,
            _liquidityForShares(baseLower, baseUpper, shares),
            address(this),
            false
        );
        (uint256 limit0, uint256 limit1) = _burnLiquidity(
            limitLower,
            limitUpper,
            _liquidityForShares(limitLower, limitUpper, shares),
            address(this),
            false
        );
    } 







    function withdraw(
        uint256 shares,
        address to,
        address from
    ) external override returns (uint256 amount0, uint256 amount1) {
        require(shares > 0, "shares");
        require(to != address(0), "to");


        (uint256 base0, uint256 base1) = _burnLiquidity(
            baseLower,
            baseUpper,
            _liquidityForShares(baseLower, baseUpper, shares),
            to,
            false
        );
        (uint256 limit0, uint256 limit1) = _burnLiquidity(
            limitLower,
            limitUpper,
            _liquidityForShares(limitLower, limitUpper, shares),
            to,
            false
        );


        uint256 totalSupply = totalSupply();
        uint256 unusedAmount0 = token0.balanceOf(address(this)).mul(shares).div(totalSupply);
        uint256 unusedAmount1 = token1.balanceOf(address(this)).mul(shares).div(totalSupply);
        if (unusedAmount0 > 0) token0.safeTransfer(to, unusedAmount0);
        if (unusedAmount1 > 0) token1.safeTransfer(to, unusedAmount1);

        amount0 = base0.add(limit0).add(unusedAmount0);
        amount1 = base1.add(limit1).add(unusedAmount1);

        require(
            from == msg.sender || IUniversalVault(from).owner() == msg.sender,
            "Sender must own the tokens"
        );
        _burn(from, shares);

        emit Withdraw(from, to, shares, amount0, amount1);
    }









    function rebalance(
        int24 _baseLower,
        int24 _baseUpper,
        int24 _limitLower,
        int24 _limitUpper,
        address feeRecipient,
        int256 swapQuantity
    ) external override onlyOwner {
        require(
            _baseLower < _baseUpper &&
                _baseLower % tickSpacing == 0 &&
                _baseUpper % tickSpacing == 0,
            "base position invalid"
        );
        require(
            _limitLower < _limitUpper &&
                _limitLower % tickSpacing == 0 &&
                _limitUpper % tickSpacing == 0,
            "limit position invalid"
        );


        (uint128 baseLiquidity, , ) = _position(baseLower, baseUpper);
        if (baseLiquidity > 0) {
            pool.burn(baseLower, baseUpper, 0);
        }
        (uint128 limitLiquidity, , ) = _position(limitLower, limitUpper);
        if (limitLiquidity > 0) {
            pool.burn(limitLower, limitUpper, 0);
        }


        (, uint256 feesLimit0, uint256 feesLimit1) = _position(baseLower, baseUpper);
        (, uint256 feesBase0, uint256 feesBase1) = _position(limitLower, limitUpper);

        uint256 fees0 = feesBase0.add(feesLimit0);
        uint256 fees1 = feesBase1.add(feesLimit1);
        _burnLiquidity(baseLower, baseUpper, baseLiquidity, address(this), true);
        _burnLiquidity(limitLower, limitUpper, limitLiquidity, address(this), true);


        if (fees0 > 0) token0.safeTransfer(feeRecipient, fees0.div(10));
        if (fees1 > 0) token1.safeTransfer(feeRecipient, fees1.div(10));

        emit Rebalance(
            currentTick(),
            token0.balanceOf(address(this)),
            token1.balanceOf(address(this)),
            fees0,
            fees1,
            totalSupply()
        );


        if (swapQuantity != 0) {
            pool.swap(
                address(this),
                swapQuantity > 0,
                swapQuantity > 0 ? swapQuantity : -swapQuantity,
                swapQuantity > 0 ? TickMath.MIN_SQRT_RATIO + 1 : TickMath.MAX_SQRT_RATIO - 1,
                abi.encode(address(this))
            );
        }

        baseLower = _baseLower;
        baseUpper = _baseUpper;
        baseLiquidity = _liquidityForAmounts(
            baseLower,
            baseUpper,
            token0.balanceOf(address(this)),
            token1.balanceOf(address(this))
        );
        _mintLiquidity(baseLower, baseUpper, baseLiquidity, address(this));

        limitLower = _limitLower;
        limitUpper = _limitUpper;
        limitLiquidity = _liquidityForAmounts(
            limitLower,
            limitUpper,
            token0.balanceOf(address(this)),
            token1.balanceOf(address(this))
        );
        _mintLiquidity(limitLower, limitUpper, limitLiquidity, address(this));
    }

    function pendingFees() external onlyOwner returns (uint256 fees0, uint256 fees1) {

        (uint128 baseLiquidity, , ) = _position(baseLower, baseUpper);
        if (baseLiquidity > 0) {
            pool.burn(baseLower, baseUpper, 0);
        }
        (uint128 limitLiquidity, , ) = _position(limitLower, limitUpper);
        if (limitLiquidity > 0) {
            pool.burn(limitLower, limitUpper, 0);
        }


        (, uint256 feesLimit0, uint256 feesLimit1) = _position(baseLower, baseUpper);
        (, uint256 feesBase0, uint256 feesBase1) = _position(limitLower, limitUpper);

        fees0 = feesBase0.add(feesLimit0);
        fees1 = feesBase1.add(feesLimit1);
    }

    function addBaseLiquidity(uint256 amount0, uint256 amount1) external onlyOwner {
        uint128 baseLiquidity = _liquidityForAmounts(
            baseLower,
            baseUpper,
            amount0 == 0 && amount1 == 0 ? token0.balanceOf(address(this)) : amount0,
            amount0 == 0 && amount1 == 0 ? token1.balanceOf(address(this)) : amount1
        );
        _mintLiquidity(baseLower, baseUpper, baseLiquidity, address(this));
    }

    function addLimitLiquidity(uint256 amount0, uint256 amount1) external onlyOwner {
        uint128 limitLiquidity = _liquidityForAmounts(
            limitLower,
            limitUpper,
            amount0 == 0 && amount1 == 0 ? token0.balanceOf(address(this)) : amount0,
            amount0 == 0 && amount1 == 0 ? token1.balanceOf(address(this)) : amount1
        );
        _mintLiquidity(limitLower, limitUpper, limitLiquidity, address(this));
    }

    function _mintLiquidity(
        int24 tickLower,
        int24 tickUpper,
        uint128 liquidity,
        address payer
    ) internal returns (uint256 amount0, uint256 amount1) {
        if (liquidity > 0) {
            (amount0, amount1) = pool.mint(
                address(this),
                tickLower,
                tickUpper,
                liquidity,
                abi.encode(payer)
            );
        }
    }

    function _burnLiquidity(
        int24 tickLower,
        int24 tickUpper,
        uint128 liquidity,
        address to,
        bool collectAll
    ) internal returns (uint256 amount0, uint256 amount1) {
        if (liquidity > 0) {

            (uint256 owed0, uint256 owed1) = pool.burn(tickLower, tickUpper, liquidity);


            uint128 collect0 = collectAll ? type(uint128).max : _uint128Safe(owed0);
            uint128 collect1 = collectAll ? type(uint128).max : _uint128Safe(owed1);
            if (collect0 > 0 || collect1 > 0) {
                (amount0, amount1) = pool.collect(to, tickLower, tickUpper, collect0, collect1);
            }
        }
    }

    function _liquidityForShares(
        int24 tickLower,
        int24 tickUpper,
        uint256 shares
    ) internal view returns (uint128) {
        (uint128 position, , ) = _position(tickLower, tickUpper);
        return _uint128Safe(uint256(position).mul(shares).div(totalSupply()));
    }

    function _position(int24 tickLower, int24 tickUpper)
        internal
        view
        returns (
            uint128 liquidity,
            uint128 tokensOwed0,
            uint128 tokensOwed1
        )
    {
        bytes32 positionKey = keccak256(abi.encodePacked(address(this), tickLower, tickUpper));
        (liquidity, , , tokensOwed0, tokensOwed1) = pool.positions(positionKey);
    }

    function uniswapV3MintCallback(
        uint256 amount0,
        uint256 amount1,
        bytes calldata data
    ) external override {
        require(msg.sender == address(pool));
        address payer = abi.decode(data, (address));

        if (payer == address(this)) {
            if (amount0 > 0) token0.safeTransfer(msg.sender, amount0);
            if (amount1 > 0) token1.safeTransfer(msg.sender, amount1);
        } else {
            if (amount0 > 0) token0.safeTransferFrom(payer, msg.sender, amount0);
            if (amount1 > 0) token1.safeTransferFrom(payer, msg.sender, amount1);
        }
    }

    function uniswapV3SwapCallback(
        int256 amount0Delta,
        int256 amount1Delta,
        bytes calldata data
    ) external override {
        require(msg.sender == address(pool));
        address payer = abi.decode(data, (address));

        if (amount0Delta > 0) {
            if (payer == address(this)) {
                token0.safeTransfer(msg.sender, uint256(amount0Delta));
            } else {
                token0.safeTransferFrom(payer, msg.sender, uint256(amount0Delta));
            }
        } else if (amount1Delta > 0) {
            if (payer == address(this)) {
                token1.safeTransfer(msg.sender, uint256(amount1Delta));
            } else {
                token1.safeTransferFrom(payer, msg.sender, uint256(amount1Delta));
            }
        }
    }



    function getTotalAmounts() public view override returns (uint256 total0, uint256 total1) {
        (, uint256 base0, uint256 base1) = getBasePosition();
        (, uint256 limit0, uint256 limit1) = getLimitPosition();
        total0 = token0.balanceOf(address(this)).add(base0).add(limit0);
        total1 = token1.balanceOf(address(this)).add(base1).add(limit1);
    }






    function getBasePosition()
        public
        view
        returns (
            uint128 liquidity,
            uint256 amount0,
            uint256 amount1
        )
    {
        (uint128 positionLiquidity, uint128 tokensOwed0, uint128 tokensOwed1) = _position(
            baseLower,
            baseUpper
        );
        (amount0, amount1) = _amountsForLiquidity(baseLower, baseUpper, positionLiquidity);
        amount0 = amount0.add(uint256(tokensOwed0));
        amount1 = amount1.add(uint256(tokensOwed1));
        liquidity = positionLiquidity;
    }






    function getLimitPosition()
        public
        view
        returns (
            uint128 liquidity,
            uint256 amount0,
            uint256 amount1
        )
    {
        (uint128 positionLiquidity, uint128 tokensOwed0, uint128 tokensOwed1) = _position(
            limitLower,
            limitUpper
        );
        (amount0, amount1) = _amountsForLiquidity(limitLower, limitUpper, positionLiquidity);
        amount0 = amount0.add(uint256(tokensOwed0));
        amount1 = amount1.add(uint256(tokensOwed1));
        liquidity = positionLiquidity;
    }

    function _amountsForLiquidity(
        int24 tickLower,
        int24 tickUpper,
        uint128 liquidity
    ) internal view returns (uint256, uint256) {
        (uint160 sqrtRatioX96, , , , , , ) = pool.slot0();
        return
            LiquidityAmounts.getAmountsForLiquidity(
                sqrtRatioX96,
                TickMath.getSqrtRatioAtTick(tickLower),
                TickMath.getSqrtRatioAtTick(tickUpper),
                liquidity
            );
    }

    function _liquidityForAmounts(
        int24 tickLower,
        int24 tickUpper,
        uint256 amount0,
        uint256 amount1
    ) internal view returns (uint128) {
        (uint160 sqrtRatioX96, , , , , , ) = pool.slot0();
        return
            LiquidityAmounts.getLiquidityForAmounts(
                sqrtRatioX96,
                TickMath.getSqrtRatioAtTick(tickLower),
                TickMath.getSqrtRatioAtTick(tickUpper),
                amount0,
                amount1
            );
    }


    function currentTick() public view returns (int24 tick) {
        (, tick, , , , , ) = pool.slot0();
    }

    function _uint128Safe(uint256 x) internal pure returns (uint128) {
        assert(x <= type(uint128).max);
        return uint128(x);
    }


    function setMaxTotalSupply(uint256 _maxTotalSupply) external onlyOwner {
        maxTotalSupply = _maxTotalSupply;
    }


    function toggleDirectDeposit() external onlyOwner {
        directDeposit = !directDeposit;
    }



    function setDepositMax(uint256 _deposit0Max, uint256 _deposit1Max) external onlyOwner {
        deposit0Max = _deposit0Max;
        deposit1Max = _deposit1Max;
    }

    function appendList(address[] memory listed) external onlyOwner {
        for (uint8 i; i < listed.length; i++) {
            list[listed[i]] = true;
        }
    }

    function removeListed(address listed) external onlyOwner {
        list[listed] = false;
    }

    function toggleWhitelist() external onlyOwner {
        whitelisted = !whitelisted;
    }

    function transferOwnership(address newOwner) external onlyOwner {
        owner = newOwner;
    }

    modifier onlyOwner {
        require(msg.sender == owner, "only owner");
        _;
    }
}

pragma abicoder v2;

import "./interfaces/IHypervisor.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@uniswap/v3-core/contracts/libraries/FullMath.sol";
import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/math/SignedSafeMath.sol";
import "@uniswap/v3-core/contracts/libraries/TickMath.sol";
import "@uniswap/v3-periphery/contracts/interfaces/ISwapRouter.sol";

contract UniProxy {
  using SafeERC20 for IERC20;
  using SafeMath for uint256;
  using SignedSafeMath for int256;

  mapping(address => Position) public positions;

  address public owner;
  bool public freeDeposit = false;
  bool public twapCheck = false;
  uint32 public twapInterval = 1 hours;
  uint256 public depositDelta = 1010;
  uint256 public deltaScale = 1000; 
  uint256 public priceThreshold = 100;
  uint256 public swapLife = 10000;
  ISwapRouter public router;

  uint256 MAX_INT = 2**256 - 1;

  struct Position {
    uint8 version; 
    mapping(address=>bool) list; 
    bool twapOverride; 
    uint32 twapInterval; 
    uint256 priceThreshold; 
    bool depositOverride; 
    uint256 deposit0Max;
    uint256 deposit1Max;
    uint256 maxTotalSupply;
    bool freeDeposit; 
  }

  constructor() {
    owner = msg.sender;
  }



  function addPosition(address pos, uint8 version) external onlyOwner {
    require(positions[pos].version == 0, 'already added');
    require(version > 0, 'version < 1');
    IHypervisor(pos).token0().approve(pos, MAX_INT);
    IHypervisor(pos).token1().approve(pos, MAX_INT);
    Position storage p = positions[pos];
    p.version = version;
  }









  function deposit(
    uint256 deposit0,
    uint256 deposit1,
    address to,
    address from,
    address pos
  ) external returns (uint256 shares) {
    require(positions[pos].version != 0, 'not added');

    if (twapCheck || positions[pos].twapOverride) {

      checkPriceChange(
        pos,
        (positions[pos].twapOverride ? positions[pos].twapInterval : twapInterval),
        (positions[pos].twapOverride ? positions[pos].priceThreshold : priceThreshold)
      );
    }

    if (!freeDeposit && !positions[pos].list[msg.sender] && !positions[pos].freeDeposit) {

      require(properDepositRatio(pos, deposit0, deposit1), "Improper ratio");
    }

    if (positions[pos].depositOverride) {
      if (positions[pos].deposit0Max > 0) {
        require(deposit0 <= positions[pos].deposit0Max, "token0 exceeds");
      }
      if (positions[pos].deposit1Max > 0) {
        require(deposit1 <= positions[pos].deposit1Max, "token1 exceeds");
      }
    }

    if (positions[pos].version < 3) {

      if (deposit0 != 0) {
        IHypervisor(pos).token0().transferFrom(msg.sender, address(this), deposit0);
      }
      if (deposit1 != 0) {
        IHypervisor(pos).token1().transferFrom(msg.sender, address(this), deposit1);
      }
      if (positions[pos].version < 2) {

        shares = IHypervisor(pos).deposit(deposit0, deposit1, address(this));
        IHypervisor(pos).transfer(to, shares);
      }
      else{

        shares = IHypervisor(pos).deposit(deposit0, deposit1, msg.sender);
      }
    }
    else {

      shares = IHypervisor(pos).deposit(deposit0, deposit1, msg.sender, msg.sender);
    }

    if (positions[pos].depositOverride) {
      require(IHypervisor(pos).totalSupply() <= positions[pos].maxTotalSupply, "supply exceeds");
    }

  }












  function depositSwap(
    int256 swapAmount, 
    uint256 deposit0,
    uint256 deposit1,
    address to,
    address from,
    bytes memory path,
    address pos,
    address _router
  ) external returns (uint256 shares) {

    if (twapCheck || positions[pos].twapOverride) {

      checkPriceChange(
        pos,
        (positions[pos].twapOverride ? positions[pos].twapInterval : twapInterval),
        (positions[pos].twapOverride ? positions[pos].priceThreshold : priceThreshold)
      );
    }

    if (!freeDeposit && !positions[pos].list[msg.sender] && !positions[pos].freeDeposit) {

      require(properDepositRatio(pos, deposit0, deposit1), "Improper ratio");
    }

    if (positions[pos].depositOverride) {
      if (positions[pos].deposit0Max > 0) {
        require(deposit0 <= positions[pos].deposit0Max, "token0 exceeds");
      }
      if (positions[pos].deposit1Max > 0) {
        require(deposit1 <= positions[pos].deposit1Max, "token1 exceeds");
      }
    }

    router = ISwapRouter(_router);
    uint256 amountOut;
    uint256 swap;
    if(swapAmount < 0) {


        swap = uint256(swapAmount * -1);
        IHypervisor(pos).token1().transferFrom(msg.sender, address(this), deposit1+swap);
        amountOut = router.exactInput(
            ISwapRouter.ExactInputParams(
                path,
                address(this),
                block.timestamp + swapLife,
                swap,
                deposit0
            )
        );
    }
    else{

        swap = uint256(swapAmount);
        IHypervisor(pos).token0().transferFrom(msg.sender, address(this), deposit0+swap);

        amountOut = router.exactInput(
            ISwapRouter.ExactInputParams(
                path,
                address(this),
                block.timestamp + swapLife,
                swap,
                deposit1
            )
        );      
    }

    require(amountOut > 0, "Swap failed");

    if (positions[pos].version < 2) {

      shares = IHypervisor(pos).deposit(deposit0, deposit1, address(this));
      IHypervisor(pos).transfer(to, shares);
    }
    else{

      shares = IHypervisor(pos).deposit(deposit0, deposit1, msg.sender);
    }

    if (positions[pos].depositOverride) {
      require(IHypervisor(pos).totalSupply() <= positions[pos].maxTotalSupply, "supply exceeds");
    }
  }







  function properDepositRatio(
    address pos,
    uint256 deposit0,
    uint256 deposit1
  ) public view returns (bool) {
    (uint256 hype0, uint256 hype1) = IHypervisor(pos).getTotalAmounts();
    if (IHypervisor(pos).totalSupply() != 0) {
      uint256 depositRatio = deposit0 == 0 ? 10e18 : deposit1.mul(1e18).div(deposit0);
      depositRatio = depositRatio > 10e18 ? 10e18 : depositRatio;
      depositRatio = depositRatio < 10e16 ? 10e16 : depositRatio;
      uint256 hypeRatio = hype0 == 0 ? 10e18 : hype1.mul(1e18).div(hype0);
      hypeRatio = hypeRatio > 10e18 ? 10e18 : hypeRatio;
      hypeRatio = hypeRatio < 10e16 ? 10e16 : hypeRatio;
      return (FullMath.mulDiv(depositRatio, deltaScale, hypeRatio) < depositDelta &&
              FullMath.mulDiv(hypeRatio, deltaScale, depositRatio) < depositDelta);
    }
    return true;
  }






  function getDepositAmount(
    address pos,
    address token,
    uint256 deposit
  ) public view returns (uint256 amountStart, uint256 amountEnd) {
    require(token == address(IHypervisor(pos).token0()) || token == address(IHypervisor(pos).token1()), "token mistmatch");
    require(deposit > 0, "deposits can't be zero");
    (uint256 total0, uint256 total1) = IHypervisor(pos).getTotalAmounts();
    if (IHypervisor(pos).totalSupply() == 0 || total0 == 0 || total1 == 0) return (0, 0);

    uint256 ratioStart = total0.mul(1e18).div(total1).mul(depositDelta).div(deltaScale);
    uint256 ratioEnd = total0.mul(1e18).div(total1).div(depositDelta).mul(deltaScale);

    if (token == address(IHypervisor(pos).token0())) {
      return (deposit.mul(1e18).div(ratioStart), deposit.mul(1e18).div(ratioEnd));
    }
    return (deposit.mul(ratioStart).div(1e18), deposit.mul(ratioEnd).div(1e18));
  }



  function checkPriceChange(
    address pos,
    uint32 _twapInterval,
    uint256 _priceThreshold
  ) public view returns (uint256 price) {
    uint160 sqrtPrice = TickMath.getSqrtRatioAtTick(IHypervisor(pos).currentTick());
    uint256 price = FullMath.mulDiv(uint256(sqrtPrice).mul(uint256(sqrtPrice)), 1e18, 2**(96 * 2));

    uint160 sqrtPriceBefore = getSqrtTwapX96(pos, _twapInterval);
    uint256 priceBefore = FullMath.mulDiv(uint256(sqrtPriceBefore).mul(uint256(sqrtPriceBefore)), 1e18, 2**(96 * 2));
    if (price.mul(100).div(priceBefore) > _priceThreshold || priceBefore.mul(100).div(price) > _priceThreshold)
      revert("Price change Overflow");
  }

  function getSqrtTwapX96(address pos, uint32 _twapInterval) public view returns (uint160 sqrtPriceX96) {
    if (_twapInterval == 0) {

      (sqrtPriceX96, , , , , , ) = IHypervisor(pos).pool().slot0();
    } 
    else {
      uint32[] memory secondsAgos = new uint32[](2);
      secondsAgos[0] = _twapInterval; 
      secondsAgos[1] = 0; 

      (int56[] memory tickCumulatives, ) = IHypervisor(pos).pool().observe(secondsAgos);


      sqrtPriceX96 = TickMath.getSqrtRatioAtTick(
      int24((tickCumulatives[1] - tickCumulatives[0]) / _twapInterval)
      );
    }
  }

  function setPriceThreshold(uint256 _priceThreshold) external onlyOwner {
    priceThreshold = _priceThreshold;
  }

  function setDepositDelta(uint256 _depositDelta) external onlyOwner {
    depositDelta = _depositDelta;
  }

  function setDeltaScale(uint256 _deltaScale) external onlyOwner {
    deltaScale = _deltaScale;
  }


  function customDeposit(
    address pos,
    uint256 deposit0Max,
    uint256 deposit1Max,
    uint256 maxTotalSupply
  ) external onlyOwner {
    positions[pos].deposit0Max = deposit0Max;
    positions[pos].deposit1Max = deposit1Max;
    positions[pos].maxTotalSupply = maxTotalSupply;
  }

  function setSwapLife(uint256 _swapLife) external onlyOwner {
    swapLife = _swapLife;
  }

  function toggleDepositFree() external onlyOwner {
    freeDeposit = !freeDeposit;
  }

  function toggleDepositFreeOverride(address pos) external onlyOwner {
    positions[pos].freeDeposit = !positions[pos].freeDeposit;
  }

  function setTwapInterval(uint32 _twapInterval) external onlyOwner {
    twapInterval = _twapInterval;
  }

  function setTwapOverride(address pos, bool twapOverride, uint32 _twapInterval) external onlyOwner {
    positions[pos].twapOverride = twapOverride;
    positions[pos].twapInterval = twapInterval;
  }

  function toggleTwap() external onlyOwner {
    twapCheck = !twapCheck;
  }

  function appendList(address pos, address[] memory listed) external onlyOwner {
    for (uint8 i; i < listed.length; i++) {
      positions[pos].list[listed[i]] = true;
    }
  }

  function removeListed(address pos, address listed) external onlyOwner {
    positions[pos].list[listed] = false;
  }

  function transferOwnership(address newOwner) external onlyOwner {
    owner = newOwner;
  }

  modifier onlyOwner {
    require(msg.sender == owner, "only owner");
    _;
  }
}

pragma solidity ^0.5.2;
pragma experimental ABIEncoderV2; 

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";

import "../lib/LibOrder.sol";
import "../lib/LibTypes.sol";
import {LibMathSigned, LibMathUnsigned} from "../lib/LibMath.sol";

import "./Position.sol";
import "./Brokerage.sol";

import "../interface/IPriceFeeder.sol";
import "../interface/IGlobalConfig.sol";


contract Perpetual is Brokerage, Position {
    using LibMathSigned for int256;
    using LibMathUnsigned for uint256;
    using LibOrder for LibTypes.Side;
    using SafeERC20 for IERC20;
    uint256 public totalAccounts;
    address[] public accountList;
    mapping(address => bool) private accountCreated;

    event CreatePerpetual();
    event CreateAccount(uint256 indexed id, address indexed guy);
    event Buy(address indexed guy, uint256 price, uint256 amount);
    event Sell(address indexed guy, uint256 price, uint256 amount);
    event Liquidate(address indexed keeper, address indexed guy, uint256 price, uint256 amount);
    event EndGlobalSettlement();

    constructor(address globalConfig, address devAddress, address collateral, uint256 collateralDecimals)
        public
        Position(collateral, collateralDecimals)
    {
        setGovernanceAddress("globalConfig", globalConfig);
        setGovernanceAddress("dev", devAddress);
        emit CreatePerpetual();
    }


    function setCashBalance(address guy, int256 amount) public onlyWhitelistAdmin {
        require(status == LibTypes.Status.SETTLING, "wrong perpetual status");
        int256 deltaAmount = amount.sub(cashBalances[guy].balance);
        cashBalances[guy].balance = amount;
        emit InternalUpdateBalance(guy, deltaAmount, amount);
    }


    function() external payable {
        revert("no payable");
    }

    function markPrice() public ammRequired returns (uint256) {
        return status == LibTypes.Status.NORMAL ? amm.currentMarkPrice() : settlementPrice;
    }

    function setBroker(address broker) public {
        setBroker(msg.sender, broker, globalConfig.brokerLockBlockCount());
    }

    function setBrokerFor(address guy, address broker) public onlyWhitelisted {
        setBroker(guy, broker, globalConfig.brokerLockBlockCount());
    }

    function depositToAccount(address guy, uint256 amount) private {
        require(guy != address(0), "invalid guy");
        deposit(guy, amount);


        if (!accountCreated[guy]) {
            emit CreateAccount(totalAccounts, guy);
            accountList.push(guy);
            totalAccounts++;
            accountCreated[guy] = true;
        }
    }

    function depositFor(address guy, uint256 amount) public onlyWhitelisted {
        require(isTokenizedCollateral(), "token not acceptable");

        depositToAccount(guy, amount);
    }

    function depositEtherFor(address guy) public payable onlyWhitelisted {
        require(!isTokenizedCollateral(), "ether not acceptable");

        depositToAccount(guy, msg.value);
    }

    function deposit(uint256 amount) public {
        require(isTokenizedCollateral(), "token not acceptable");

        depositToAccount(msg.sender, amount);
    }

    function depositEther() public payable {
        require(!isTokenizedCollateral(), "ether not acceptable");

        depositToAccount(msg.sender, msg.value);
    }



    function depositAndSetBroker(uint256 amount, address broker) public {
        setBroker(broker);
        if (amount > 0) {
            deposit(amount);
        }
    }



    function depositEtherAndSetBroker(address broker) public payable {
        setBroker(broker);
        if (msg.value > 0) {
            depositEther();
        }
    }

    function applyForWithdrawal(uint256 amount) public {
        applyForWithdrawal(msg.sender, amount, globalConfig.withdrawalLockBlockCount());
    }

    function settleFor(address guy) private {
        uint256 currentMarkPrice = markPrice();
        LibTypes.PositionAccount memory account = positions[guy];
        if (account.size > 0) {
            int256 pnl = close(account, currentMarkPrice, account.size);
            updateBalance(guy, pnl);
            positions[guy] = account;
        }
        emit UpdatePositionAccount(guy, account, totalSize(LibTypes.Side.LONG), currentMarkPrice);
    }

    function settle() public {
        require(status == LibTypes.Status.SETTLED, "wrong perpetual status");

        address payable guy = msg.sender;
        settleFor(guy);
        withdrawAll(guy);
    }

    function endGlobalSettlement() public onlyWhitelistAdmin {
        require(status == LibTypes.Status.SETTLING, "wrong perpetual status");

        address guy = address(amm.perpetualProxy());
        settleFor(guy);
        status = LibTypes.Status.SETTLED;

        emit EndGlobalSettlement();
    }

    function withdrawFromAccount(address payable guy, uint256 amount) private {
        require(guy != address(0), "invalid guy");
        require(status != LibTypes.Status.SETTLING, "wrong perpetual status");

        uint256 currentMarkPrice = markPrice();
        require(isSafeWithPrice(guy, currentMarkPrice), "unsafe before withdraw");
        remargin(guy, currentMarkPrice);
        address broker = currentBroker(guy);
        bool forced = broker == address(amm.perpetualProxy()) || broker == address(0);
        withdraw(guy, amount, forced);

        require(isSafeWithPrice(guy, currentMarkPrice), "unsafe after withdraw");
        require(availableMarginWithPrice(guy, currentMarkPrice) >= 0, "withdraw margin");
    }

    function withdrawFor(address payable guy, uint256 amount) public onlyWhitelisted {
        require(status == LibTypes.Status.NORMAL, "wrong perpetual status");
        withdrawFromAccount(guy, amount);
    }

    function withdraw(uint256 amount) public {
        withdrawFromAccount(msg.sender, amount);
    }

    function depositToInsuranceFund(uint256 rawAmount) public {
        require(isTokenizedCollateral(), "token not acceptable");
        require(rawAmount > 0, "invalid amount");

        int256 wadAmount = depositToProtocol(msg.sender, rawAmount);
        insuranceFundBalance = insuranceFundBalance.add(wadAmount);

        require(insuranceFundBalance >= 0, "negtive insurance fund");

        emit UpdateInsuranceFund(insuranceFundBalance);
    }

    function depositEtherToInsuranceFund() public payable {
        require(!isTokenizedCollateral(), "ether not acceptable");
        require(msg.value > 0, "invalid amount");

        int256 wadAmount = depositToProtocol(msg.sender, msg.value);
        insuranceFundBalance = insuranceFundBalance.add(wadAmount);

        require(insuranceFundBalance >= 0, "negtive insurance fund");

        emit UpdateInsuranceFund(insuranceFundBalance);
    }

    function withdrawFromInsuranceFund(uint256 rawAmount) public onlyWhitelistAdmin {
        require(rawAmount > 0, "invalid amount");
        require(insuranceFundBalance > 0, "insufficient funds");
        require(rawAmount <= insuranceFundBalance.toUint256(), "insufficient funds");

        int256 wadAmount = toWad(rawAmount);
        insuranceFundBalance = insuranceFundBalance.sub(wadAmount);
        withdrawFromProtocol(msg.sender, rawAmount);

        require(insuranceFundBalance >= 0, "negtive insurance fund");

        emit UpdateInsuranceFund(insuranceFundBalance);
    }

    function positionMargin(address guy) public returns (uint256) {
        return Position.marginWithPrice(guy, markPrice());
    }

    function maintenanceMargin(address guy) public returns (uint256) {
        return maintenanceMarginWithPrice(guy, markPrice());
    }

    function marginBalance(address guy) public returns (int256) {
        return marginBalanceWithPrice(guy, markPrice());
    }

    function pnl(address guy) public returns (int256) {
        return pnlWithPrice(guy, markPrice());
    }

    function availableMargin(address guy) public returns (int256) {
        return availableMarginWithPrice(guy, markPrice());
    }

    function drawableBalance(address guy) public returns (int256) {
        return drawableBalanceWithPrice(guy, markPrice());
    }


    function isSafe(address guy) public returns (bool) {
        uint256 currentMarkPrice = markPrice();
        return isSafeWithPrice(guy, currentMarkPrice);
    }


    function isSafeWithPrice(address guy, uint256 currentMarkPrice) public returns (bool) {
        return
            marginBalanceWithPrice(guy, currentMarkPrice) >=
            maintenanceMarginWithPrice(guy, currentMarkPrice).toInt256();
    }

    function isBankrupt(address guy) public returns (bool) {
        return marginBalanceWithPrice(guy, markPrice()) < 0;
    }


    function isIMSafe(address guy) public returns (bool) {
        uint256 currentMarkPrice = markPrice();
        return isIMSafeWithPrice(guy, currentMarkPrice);
    }


    function isIMSafeWithPrice(address guy, uint256 currentMarkPrice) public returns (bool) {
        return availableMarginWithPrice(guy, currentMarkPrice) >= 0;
    }

    function liquidateFrom(address from, address guy, uint256 maxAmount) public returns (uint256, uint256) {
        require(maxAmount.mod(governance.lotSize) == 0, "invalid lot size");
        require(!isSafe(guy), "safe account");

        uint256 liquidationPrice = markPrice();
        uint256 liquidationAmount = calculateLiquidateAmount(guy, liquidationPrice);
        uint256 totalPositionSize = positions[guy].size;
        uint256 liquidatableAmount = totalPositionSize.sub(totalPositionSize.mod(governance.lotSize));
        liquidationAmount = liquidationAmount.ceil(governance.lotSize).min(maxAmount).min(liquidatableAmount);
        require(liquidationAmount > 0, "nothing to liquidate");

        uint256 opened = liquidate(from, guy, liquidationPrice, liquidationAmount);
        if (opened > 0) {
            require(availableMarginWithPrice(from, liquidationPrice) >= 0, "liquidator margin");
        } else {
            require(isSafe(from), "liquidator unsafe");
        }

        emit Liquidate(from, guy, liquidationPrice, liquidationAmount);
    }

    function liquidate(address guy, uint256 maxAmount) public returns (uint256, uint256) {
        require(status != LibTypes.Status.SETTLED, "wrong perpetual status");
        return liquidateFrom(msg.sender, guy, maxAmount);
    }

    function tradePosition(address trader, LibTypes.Side side, uint256 price, uint256 amount)
        public
        onlyWhitelisted
        returns (uint256)
    {
        require(status != LibTypes.Status.SETTLING, "wrong perpetual status");
        require(side == LibTypes.Side.LONG || side == LibTypes.Side.SHORT, "invalid side");

        uint256 opened = Position.trade(trader, side, price, amount);
        if (side == LibTypes.Side.LONG) {
            emit Buy(trader, price, amount);
        } else if (side == LibTypes.Side.SHORT) {
            emit Sell(trader, price, amount);
        }
        return opened;
    }

    function transferCashBalance(address from, address to, uint256 amount) public onlyWhitelisted {
        require(status != LibTypes.Status.SETTLING, "wrong perpetual status");
        transferBalance(from, to, amount.toInt256());
    }
}

pragma solidity >=0.7.0 <0.8.0;


import "@openzeppelin/contracts-upgradeable/proxy/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/token/ERC20/IERC20Upgradeable.sol";


import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@pooltogether/fixed-point/contracts/FixedPoint.sol";





import "./libraries/ExtendedSafeCast.sol";


contract TokenDrop is Initializable {

    using SafeMath for uint256;
    using ExtendedSafeCast for uint256;



    IERC20Upgradeable public asset;


    IERC20Upgradeable public measure;


    uint112 public exchangeRateMantissa;


    uint112 public totalUnclaimed;


    uint32 public lastDripTimestamp;


    address public factory;


    event Dripped(uint256 newTokens);

    event Deposited(address indexed user, uint256 amount);

    event Claimed(address indexed user, uint256 newTokens);


    struct UserState {
        uint128 lastExchangeRateMantissa;
        uint256 balance;
    }


    mapping(address => UserState) public userStates;




    function initialize(address _measure, address _asset) external {
        measure = IERC20Upgradeable(_measure);
        asset = IERC20Upgradeable(_asset);


        factory = msg.sender;
    }




    function beforeTokenTransfer(
        address from,
        address to,
        address token
    ) external {

        if (token == address(measure)) {
            drop();


            _captureNewTokensForUser(to);


            if (from != address(0)) {
                _captureNewTokensForUser(from);
            }
        }
    }


    function addAssetToken(uint256 amount) external returns (bool) {

        asset.transferFrom(msg.sender, address(this), amount);


        drop();


        return true;
    }



    function claim(address user) external returns (uint256) {
        drop();
        _captureNewTokensForUser(user);
        uint256 balance = userStates[user].balance;
        userStates[user].balance = 0;
        totalUnclaimed = uint256(totalUnclaimed).sub(balance).toUint112();


        asset.transfer(user, balance);


        emit Claimed(user, balance);

        return balance;
    }




    function drop() public returns (uint256) {
        uint256 assetTotalSupply = asset.balanceOf(address(this));
        uint256 newTokens = assetTotalSupply.sub(totalUnclaimed);


        if (newTokens > 0) {

            uint256 measureTotalSupply = measure.totalSupply();


            if (measureTotalSupply > 0) {
                uint256 indexDeltaMantissa =
                    FixedPoint.calculateMantissa(newTokens, measureTotalSupply);
                uint256 nextExchangeRateMantissa =
                    uint256(exchangeRateMantissa).add(indexDeltaMantissa);

                exchangeRateMantissa = nextExchangeRateMantissa.toUint112();
                totalUnclaimed = uint256(totalUnclaimed)
                    .add(newTokens)
                    .toUint112();
            }

            emit Dripped(newTokens);
        }

        return newTokens;
    }




    function _captureNewTokensForUser(address user) private returns (uint128) {
        UserState storage userState = userStates[user];
        if (exchangeRateMantissa == userState.lastExchangeRateMantissa) {

            return 0;
        }
        uint256 deltaExchangeRateMantissa =
            uint256(exchangeRateMantissa).sub(
                userState.lastExchangeRateMantissa
            );
        uint256 userMeasureBalance = measure.balanceOf(user);
        uint128 newTokens =
            FixedPoint
                .multiplyUintByMantissa(
                userMeasureBalance,
                deltaExchangeRateMantissa
            )
                .toUint128();

        userStates[user] = UserState({
            lastExchangeRateMantissa: exchangeRateMantissa,
            balance: uint256(userState.balance).add(newTokens).toUint128()
        });

        return newTokens;
    }

    function supportsInterface(bytes4 interfaceId)
        external
        view
        returns (bool)
    {
        return true;
    }
}

pragma solidity ^0.5.3;
pragma experimental ABIEncoderV2;

import "../Permissions.sol";
import "./DelegationController.sol";
import "./TimeHelpers.sol";



contract TokenState is Permissions {

    enum State {
        PROPOSED,
        ACCEPTED,
        DELEGATED,
        ENDING_DELEGATED,
        COMPLETED
    }


    mapping (uint => State) private _state;


    mapping (uint => uint) private _timelimit;


    mapping (address => uint) private _purchased;

    mapping (address => uint) private _slashed;

    mapping (address => uint) private _totalDelegated;

    mapping (uint => bool) private _isPurchased;


    mapping (address => uint[]) private _endingDelegations;

    constructor(address _contractManager) Permissions(_contractManager) public {
    }

    function getLockedCount(address holder) external returns (uint amount) {
        amount = 0;
        DelegationController delegationController = DelegationController(contractManager.getContract("DelegationController"));
        uint[] memory delegationIds = delegationController.getDelegationsByHolder(holder);

        for (uint i = 0; i < delegationIds.length; ++i) {
            uint id = delegationIds[i];
            if (isLocked(getState(id))) {
                amount += delegationController.getDelegation(id).amount;
            }
        }
        return amount + getPurchasedAmount(holder) + this.getSlashedAmount(holder);
    }

    function getDelegatedCount(address holder) external returns (uint amount) {
        amount = 0;
        DelegationController delegationController = DelegationController(contractManager.getContract("DelegationController"));
        uint[] memory delegationIds = delegationController.getDelegationsByHolder(holder);
        for (uint i = 0; i < delegationIds.length; ++i) {
            uint id = delegationIds[i];
            if (isDelegated(getState(id))) {
                amount += delegationController.getDelegation(id).amount;
            }
        }
        return amount;
    }

    function sold(address holder, uint amount) external allow("DelegationService") {
        _purchased[holder] += amount;
    }

    function accept(uint delegationId) external allow("DelegationRequestManager") {
        require(getState(delegationId) == State.PROPOSED, "Can't set state to accepted");
        setState(delegationId, State.ACCEPTED);
    }

    function requestUndelegation(uint delegationId) external allow("DelegationService") {
        require(getState(delegationId) == State.DELEGATED, "Can't request undelegation");
        setState(delegationId, State.ENDING_DELEGATED);
    }

    function cancel(uint delegationId) external allow("DelegationRequestManager") returns (State state) {
        require(getState(delegationId) == State.PROPOSED, "Can't cancel delegation request");
        DelegationController delegationController = DelegationController(contractManager.getContract("DelegationController"));
        return _cancel(delegationId, delegationController.getDelegation(delegationId));
    }

    function slash(uint delegationId, uint amount) external allow("DelegationService") {
        DelegationController delegationController = DelegationController(contractManager.getContract("DelegationController"));
        DelegationController.Delegation memory delegation = delegationController.getDelegation(delegationId);
        uint slashingAmount = amount;
        if (delegation.amount < amount) {

            slashingAmount = delegation.amount;
        }
        _slashed[delegation.holder] += slashingAmount;
        delegationController.setDelegationAmount(delegationId, delegation.amount - slashingAmount);
    }

    function forgive(address wallet, uint amount) external allow("DelegationService") {
        uint forgiveAmount = amount;
        if (amount > _slashed[wallet]) {
            forgiveAmount = _slashed[wallet];
        }
        _slashed[wallet] -= forgiveAmount;
    }

    function getSlashedAmount(address holder) external returns (uint amount) {
        return _slashed[holder];
    }

    function getState(uint delegationId) public returns (State state) {
        DelegationController delegationController = DelegationController(contractManager.getContract("DelegationController"));

        require(delegationController.getDelegation(delegationId).holder != address(0), "Delegation does not exists");
        state = _state[delegationId];
        if (state == State.PROPOSED) {
            if (_timelimit[delegationId] == 0) {
                initProposed(delegationId);
            }
            if (now >= _timelimit[delegationId]) {
                state = _cancel(delegationId, delegationController.getDelegation(delegationId));
            }
        } else if (state == State.ACCEPTED) {
            if (now >= _timelimit[delegationId]) {
                state = acceptedToDelegated(delegationId);
                uint validatorId = delegationController.getDelegation(delegationId).validatorId;
                uint amount = delegationController.getDelegation(delegationId).amount;
                delegationController.addDelegationsTotal(validatorId, amount);
            }
        } else if (state == State.ENDING_DELEGATED) {
            if (now >= _timelimit[delegationId]) {
                state = endingDelegatedToUnlocked(delegationId, delegationController.getDelegation(delegationId));
                uint validatorId = delegationController.getDelegation(delegationId).validatorId;
                uint amount = delegationController.getDelegation(delegationId).amount;
                delegationController.subDelegationsTotal(validatorId, amount);
            }
        }
    }

    function getPurchasedAmount(address holder) public returns (uint amount) {

        for (uint i = 0; i < _endingDelegations[holder].length; ++i) {
            getState(_endingDelegations[holder][i]);
        }
        return _purchased[holder];
    }

    function isDelegated(State state) public returns (bool) {
        return state == State.DELEGATED || state == State.ENDING_DELEGATED;
    }



    function setState(uint delegationId, State newState) internal {
        TimeHelpers timeHelpers = TimeHelpers(contractManager.getContract("TimeHelpers"));
        DelegationController delegationController = DelegationController(contractManager.getContract("DelegationController"));

        require(newState != State.PROPOSED, "Can't set state to proposed");

        if (newState == State.ACCEPTED) {
            State currentState = getState(delegationId);
            require(currentState == State.PROPOSED, "Can't set state to accepted");

            _state[delegationId] = State.ACCEPTED;
            _timelimit[delegationId] = timeHelpers.getNextMonthStart();
        } else if (newState == State.DELEGATED) {
            revert("Can't set state to delegated");
        } else if (newState == State.ENDING_DELEGATED) {
            require(getState(delegationId) == State.DELEGATED, "Can't set state to ending delegated");
            DelegationController.Delegation memory delegation = delegationController.getDelegation(delegationId);

            _state[delegationId] = State.ENDING_DELEGATED;
            _timelimit[delegationId] = timeHelpers.calculateDelegationEndTime(delegation.created, delegation.delegationPeriod, 3);
            _endingDelegations[delegation.holder].push(delegationId);
        } else {
            revert("Unknown state");
        }
    }

    function initProposed(uint delegationId) internal {
        TimeHelpers timeHelpers = TimeHelpers(contractManager.getContract("TimeHelpers"));
        DelegationController delegationController = DelegationController(contractManager.getContract("DelegationController"));
        DelegationController.Delegation memory delegation = delegationController.getDelegation(delegationId);

        _timelimit[delegationId] = timeHelpers.getNextMonthStartFromDate(delegation.created);
        if (_purchased[delegation.holder] > 0) {
            _isPurchased[delegationId] = true;
            if (_purchased[delegation.holder] > delegation.amount) {
                _purchased[delegation.holder] -= delegation.amount;
            } else {
                _purchased[delegation.holder] = 0;
            }
        } else {
            _isPurchased[delegationId] = false;
        }
    }

    function isLocked(State state) internal returns (bool) {
        return state != State.COMPLETED;
    }

    function proposedToUnlocked(uint delegationId) internal returns (State state) {
        state = State.COMPLETED;
        _state[delegationId] = state;
        _timelimit[delegationId] = 0;
    }

    function acceptedToDelegated(uint delegationId) internal returns (State state) {
        state = State.DELEGATED;
        _state[delegationId] = state;
        _timelimit[delegationId] = 0;
    }

    function purchasedProposedToPurchased(uint delegationId, DelegationController.Delegation memory delegation) internal returns (State state) {
        state = State.COMPLETED;
        _state[delegationId] = state;
        _timelimit[delegationId] = 0;
        _purchased[delegation.holder] += delegation.amount;
    }

    function endingDelegatedToUnlocked(uint delegationId, DelegationController.Delegation memory delegation) internal returns (State state) {
        state = State.COMPLETED;
        _state[delegationId] = state;
        _timelimit[delegationId] = 0;


        uint endingLength = _endingDelegations[delegation.holder].length;
        for (uint i = 0; i < endingLength; ++i) {
            if (_endingDelegations[delegation.holder][i] == delegationId) {
                for (uint j = i; j + 1 < endingLength; ++j) {
                    _endingDelegations[delegation.holder][j] = _endingDelegations[delegation.holder][j+1];
                }
                _endingDelegations[delegation.holder][endingLength - 1] = 0;
                --_endingDelegations[delegation.holder].length;
                break;
            }
        }

        if (_isPurchased[delegationId]) {
            address holder = delegation.holder;
            _totalDelegated[holder] += delegation.amount;
            if (_totalDelegated[holder] >= _purchased[holder]) {
                purchasedToUnlocked(holder);
            }
        }
    }

    function purchasedToUnlocked(address holder) internal {
        _purchased[holder] = 0;
        _totalDelegated[holder] = 0;
    }

    function _cancel(uint delegationId, DelegationController.Delegation memory delegation) internal returns (State state) {
        if (_isPurchased[delegationId]) {
            state = purchasedProposedToPurchased(delegationId, delegation);
        } else {
            state = proposedToUnlocked(delegationId);
        }
    }

}

pragma solidity 0.5.3;

import "./oz/SafeMath.sol";
import "./oz/IERC20.sol";
import "./oz/ReentrancyGuard.sol";
import "./GuildBank.sol";

contract Moloch is ReentrancyGuard {
    using SafeMath for uint256;


    address public summoner; 

    uint256 public periodDuration; 
    uint256 public votingPeriodLength; 
    uint256 public gracePeriodLength; 
    uint256 public emergencyProcessingWait; 
    uint256 public bailoutWait; 
    uint256 public proposalDeposit; 
    uint256 public dilutionBound; 
    uint256 public processingReward; 
    uint256 public summoningTime; 

    IERC20 public depositToken; 
    GuildBank public guildBank; 




    uint256 constant MAX_VOTING_PERIOD_LENGTH = 10**18; 
    uint256 constant MAX_GRACE_PERIOD_LENGTH = 10**18; 
    uint256 constant MAX_BAILOUT_WAIT = 10**18; 
    uint256 constant MAX_DILUTION_BOUND = 10**18; 
    uint256 constant MAX_NUMBER_OF_SHARES_AND_LOOT = 10**18; 




    event SubmitProposal(uint256 proposalIndex, address indexed delegateKey, address indexed memberAddress, address indexed applicant, uint256 sharesRequested, uint256 lootRequested, uint256 tributeOffered, address tributeToken, uint256 paymentRequested, address paymentToken);
    event SponsorProposal(address indexed delegateKey, address indexed memberAddress, uint256 proposalIndex, uint256 proposalQueueIndex, uint256 startingPeriod);
    event SubmitVote(uint256 indexed proposalIndex, address indexed delegateKey, address indexed memberAddress, uint8 uintVote);
    event ProcessProposal(uint256 indexed proposalIndex, uint256 indexed proposalId, bool didPass);
    event Ragequit(address indexed memberAddress, uint256 sharesToBurn, uint256 lootToBurn);
    event CancelProposal(uint256 indexed proposalIndex, address applicantAddress);
    event UpdateDelegateKey(address indexed memberAddress, address newDelegateKey);
    event SummonComplete(address indexed summoner, uint256 shares);




    uint256 public proposalCount = 0; 
    uint256 public totalShares = 0; 
    uint256 public totalLoot = 0; 

    bool public emergencyWarning = false; 
    uint256 public lastEmergencyProposalIndex = 0; 

    enum Vote {
        Null, 
        Yes,
        No
    }

    struct Member {
        address delegateKey; 
        uint256 shares; 
        uint256 loot; 
        bool exists; 
        uint256 highestIndexYesVote; 
        uint256 jailed; 
    }

    struct Proposal {
        address applicant; 
        address proposer; 
        address sponsor; 
        uint256 sharesRequested; 
        uint256 lootRequested; 
        uint256 tributeOffered; 
        IERC20 tributeToken; 
        uint256 paymentRequested; 
        IERC20 paymentToken; 
        uint256 startingPeriod; 
        uint256 yesVotes; 
        uint256 noVotes; 
        bool[6] flags; 
        string details; 
        uint256 maxTotalSharesAndLootAtYesVote; 
        mapping(address => Vote) votesByMember; 
    }

    mapping(address => bool) public tokenWhitelist;
    IERC20[] public approvedTokens;

    mapping(address => bool) public proposedToWhitelist;
    mapping(address => bool) public proposedToKick;

    mapping(address => Member) public members;
    mapping(address => address) public memberAddressByDelegateKey;

    mapping(uint256 => Proposal) public proposals;

    uint256[] public proposalQueue;

    modifier onlyMember {
        require(members[msg.sender].shares > 0 || members[msg.sender].loot > 0, "not a member");
        _;
    }

    modifier onlyShareholder {
        require(members[msg.sender].shares > 0, "not a shareholder");
        _;
    }

    modifier onlyDelegate {
        require(members[memberAddressByDelegateKey[msg.sender]].shares > 0, "not a delegate");
        _;
    }

    constructor(
        address _summoner,
        address[] memory _approvedTokens,
        uint256 _periodDuration,
        uint256 _votingPeriodLength,
        uint256 _gracePeriodLength,
        uint256 _emergencyProcessingWait,
        uint256 _bailoutWait,
        uint256 _proposalDeposit,
        uint256 _dilutionBound,
        uint256 _processingReward
    ) public {
        require(_summoner != address(0), "summoner cannot be 0");
        require(_periodDuration > 0, "_periodDuration cannot be 0");
        require(_votingPeriodLength > 0, "_votingPeriodLength cannot be 0");
        require(_votingPeriodLength <= MAX_VOTING_PERIOD_LENGTH, "_votingPeriodLength exceeds limit");
        require(_gracePeriodLength <= MAX_GRACE_PERIOD_LENGTH, "_gracePeriodLength exceeds limit");
        require(_emergencyProcessingWait > 0, "_emergencyProcessingWait cannot be 0");
        require(_bailoutWait > _emergencyProcessingWait, "_bailoutWait must be greater than _emergencyProcessingWait");
        require(_bailoutWait <= MAX_BAILOUT_WAIT, "_bailoutWait exceeds limit");
        require(_dilutionBound > 0, "_dilutionBound cannot be 0");
        require(_dilutionBound <= MAX_DILUTION_BOUND, "_dilutionBound exceeds limit");
        require(_approvedTokens.length > 0, "need at least one approved token");
        require(_proposalDeposit >= _processingReward, "_proposalDeposit cannot be smaller than _processingReward");

        summoner = _summoner;

        depositToken = IERC20(_approvedTokens[0]);

        for (uint256 i = 0; i < _approvedTokens.length; i++) {
            require(_approvedTokens[i] != address(0), "_approvedToken cannot be 0");
            require(!tokenWhitelist[_approvedTokens[i]], "duplicate approved token");
            tokenWhitelist[_approvedTokens[i]] = true;
            approvedTokens.push(IERC20(_approvedTokens[i]));
        }

        guildBank = new GuildBank();

        periodDuration = _periodDuration;
        votingPeriodLength = _votingPeriodLength;
        gracePeriodLength = _gracePeriodLength;
        emergencyProcessingWait = _emergencyProcessingWait;
        bailoutWait = _bailoutWait;
        proposalDeposit = _proposalDeposit;
        dilutionBound = _dilutionBound;
        processingReward = _processingReward;

        summoningTime = now;

        members[summoner] = Member(summoner, 1, 0, true, 0, 0);
        memberAddressByDelegateKey[summoner] = summoner;
        totalShares = 1;

        emit SummonComplete(summoner, 1);
    }


    function submitProposal(
        address applicant,
        uint256 sharesRequested,
        uint256 lootRequested,
        uint256 tributeOffered,
        address tributeToken,
        uint256 paymentRequested,
        address paymentToken,
        string memory details
    ) public nonReentrant returns (uint256 proposalId) {
        require(sharesRequested.add(lootRequested) <= MAX_NUMBER_OF_SHARES_AND_LOOT, "too many shares requested");
        require(tokenWhitelist[tributeToken], "tributeToken is not whitelisted");
        require(tokenWhitelist[paymentToken], "payment is not whitelisted");
        require(applicant != address(0), "applicant cannot be 0");
        require(members[applicant].jailed == 0, "proposal applicant must not be jailed");


        require(IERC20(tributeToken).transferFrom(msg.sender, address(this), tributeOffered), "tribute token transfer failed");

        bool[6] memory flags;

        _submitProposal(applicant, sharesRequested, lootRequested, tributeOffered, tributeToken, paymentRequested, paymentToken, details, flags);
        return proposalCount - 1; 
    }

    function submitWhitelistProposal(address tokenToWhitelist, string memory details) public nonReentrant returns (uint256 proposalId) {
        require(tokenToWhitelist != address(0), "must provide token address");
        require(!tokenWhitelist[tokenToWhitelist], "cannot already have whitelisted the token");

        bool[6] memory flags;
        flags[4] = true;

        _submitProposal(address(0), 0, 0, 0, tokenToWhitelist, 0, address(0), details, flags);
        return proposalCount - 1;
    }

    function submitGuildKickProposal(address memberToKick, string memory details) public nonReentrant returns (uint256 proposalId) {
        Member memory member = members[memberToKick];

        require(member.shares > 0 || member.loot > 0, "member must have at least one share or one loot");
        require(memberToKick != summoner, "the summoner may not be kicked");
        require(members[memberToKick].jailed == 0, "member must not already be jailed");

        bool[6] memory flags;
        flags[5] = true;

        _submitProposal(memberToKick, 0, 0, 0, address(0), 0, address(0), details, flags);
        return proposalCount - 1;
    }

    function _submitProposal(
        address applicant,
        uint256 sharesRequested,
        uint256 lootRequested,
        uint256 tributeOffered,
        address tributeToken,
        uint256 paymentRequested,
        address paymentToken,
        string memory details,
        bool[6] memory flags
    ) internal {
        Proposal memory proposal = Proposal({
            applicant : applicant,
            proposer : msg.sender,
            sponsor : address(0),
            sharesRequested : sharesRequested,
            lootRequested : lootRequested,
            tributeOffered : tributeOffered,
            tributeToken : IERC20(tributeToken),
            paymentRequested : paymentRequested,
            paymentToken : IERC20(paymentToken),
            startingPeriod : 0,
            yesVotes : 0,
            noVotes : 0,
            flags : flags,
            details : details,
            maxTotalSharesAndLootAtYesVote : 0
        });

        proposals[proposalCount] = proposal;
        address memberAddress = memberAddressByDelegateKey[msg.sender];
        emit SubmitProposal(proposalCount, msg.sender, memberAddress, applicant, sharesRequested, lootRequested, tributeOffered, tributeToken, paymentRequested, paymentToken);
        proposalCount += 1;
    }

    function sponsorProposal(uint256 proposalId) public nonReentrant onlyDelegate {

        require(depositToken.transferFrom(msg.sender, address(this), proposalDeposit), "proposal deposit token transfer failed");

        Proposal storage proposal = proposals[proposalId];

        require(proposal.proposer != address(0), 'proposal must have been proposed');
        require(!proposal.flags[0], "proposal has already been sponsored");
        require(!proposal.flags[3], "proposal has been cancelled");
        require(members[proposal.applicant].jailed == 0, "proposal applicant must not be jailed");


        if (proposal.flags[4]) {
            require(!tokenWhitelist[address(proposal.tributeToken)], "cannot already have whitelisted the token");
            require(!proposedToWhitelist[address(proposal.tributeToken)], 'already proposed to whitelist');
            proposedToWhitelist[address(proposal.tributeToken)] = true;


        } else if (proposal.flags[5]) {
            require(!proposedToKick[proposal.applicant], 'already proposed to kick');
            proposedToKick[proposal.applicant] = true;
        }


        uint256 startingPeriod = max(
            getCurrentPeriod(),
            proposalQueue.length == 0 ? 0 : proposals[proposalQueue[proposalQueue.length.sub(1)]].startingPeriod
        ).add(1);

        proposal.startingPeriod = startingPeriod;

        address memberAddress = memberAddressByDelegateKey[msg.sender];
        proposal.sponsor = memberAddress;

        proposal.flags[0] = true;


        proposalQueue.push(proposalId);
        emit SponsorProposal(msg.sender, memberAddress, proposalId, proposalQueue.length.sub(1), startingPeriod);
    }

    function submitVote(uint256 proposalIndex, uint8 uintVote) public nonReentrant onlyDelegate {
        address memberAddress = memberAddressByDelegateKey[msg.sender];
        Member storage member = members[memberAddress];

        require(proposalIndex < proposalQueue.length, "proposal does not exist");
        Proposal storage proposal = proposals[proposalQueue[proposalIndex]];

        require(uintVote < 3, "must be less than 3");
        Vote vote = Vote(uintVote);

        require(getCurrentPeriod() >= proposal.startingPeriod, "voting period has not started");
        require(!hasVotingPeriodExpired(proposal.startingPeriod), "proposal voting period has expired");
        require(proposal.votesByMember[memberAddress] == Vote.Null, "member has already voted");
        require(vote == Vote.Yes || vote == Vote.No, "vote must be either Yes or No");

        proposal.votesByMember[memberAddress] = vote;

        if (vote == Vote.Yes) {
            proposal.yesVotes = proposal.yesVotes.add(member.shares);


            if (proposalIndex > member.highestIndexYesVote) {
                member.highestIndexYesVote = proposalIndex;
            }


            if (totalShares.add(totalLoot) > proposal.maxTotalSharesAndLootAtYesVote) {
                proposal.maxTotalSharesAndLootAtYesVote = totalShares.add(totalLoot);
            }

        } else if (vote == Vote.No) {
            proposal.noVotes = proposal.noVotes.add(member.shares);
        }

        emit SubmitVote(proposalIndex, msg.sender, memberAddress, uintVote);
    }

    function processProposal(uint256 proposalIndex) public nonReentrant {
        _validateProposalForProcessing(proposalIndex);

        uint256 proposalId = proposalQueue[proposalIndex];
        Proposal storage proposal = proposals[proposalId];

        require(!proposal.flags[4] && !proposal.flags[5], "must be a standard proposal");

        proposal.flags[1] = true; 

        (bool didPass, bool emergencyProcessing) = _didPass(proposalIndex);


        if (totalShares.add(totalLoot).add(proposal.sharesRequested).add(proposal.lootRequested) > MAX_NUMBER_OF_SHARES_AND_LOOT) {
            didPass = false;
        }


        if (!emergencyProcessing && proposal.paymentToken != IERC20(0) && proposal.paymentRequested > proposal.paymentToken.balanceOf(address(guildBank))) {
            didPass = false;
        }


        if (didPass) {
            proposal.flags[2] = true; 


            if (members[proposal.applicant].exists) {
                members[proposal.applicant].shares = members[proposal.applicant].shares.add(proposal.sharesRequested);
                members[proposal.applicant].loot = members[proposal.applicant].loot.add(proposal.lootRequested);


            } else {

                if (members[memberAddressByDelegateKey[proposal.applicant]].exists) {
                    address memberToOverride = memberAddressByDelegateKey[proposal.applicant];
                    memberAddressByDelegateKey[memberToOverride] = memberToOverride;
                    members[memberToOverride].delegateKey = memberToOverride;
                }


                members[proposal.applicant] = Member(proposal.applicant, proposal.sharesRequested, proposal.lootRequested, true, 0, 0);
                memberAddressByDelegateKey[proposal.applicant] = proposal.applicant;
            }


            totalShares = totalShares.add(proposal.sharesRequested);
            totalLoot = totalLoot.add(proposal.lootRequested);

            require(
                proposal.tributeToken.transfer(address(guildBank), proposal.tributeOffered),
                "token transfer to guild bank failed"
            );

            require(
                guildBank.withdrawToken(proposal.paymentToken, proposal.applicant, proposal.paymentRequested),
                "token payment to applicant failed"
            );



        } else {


            if (!emergencyProcessing) {
                require(
                    proposal.tributeToken.transfer(proposal.proposer, proposal.tributeOffered),
                    "failing vote token transfer failed"
                );
            }
        }

        _returnDeposit(proposal.sponsor);

        emit ProcessProposal(proposalIndex, proposalId, didPass);
    }

    function processWhitelistProposal(uint256 proposalIndex) public nonReentrant {
        _validateProposalForProcessing(proposalIndex);

        uint256 proposalId = proposalQueue[proposalIndex];
        Proposal storage proposal = proposals[proposalId];

        require(proposal.flags[4], "must be a whitelist proposal");

        proposal.flags[1] = true; 

        (bool didPass,) = _didPass(proposalIndex);

        if (didPass) {
            proposal.flags[2] = true; 

            tokenWhitelist[address(proposal.tributeToken)] = true;
            approvedTokens.push(proposal.tributeToken);
        }

        proposedToWhitelist[address(proposal.tributeToken)] = false;

        _returnDeposit(proposal.sponsor);

        emit ProcessProposal(proposalIndex, proposalId, didPass);
    }

    function processGuildKickProposal(uint256 proposalIndex) public nonReentrant {
        _validateProposalForProcessing(proposalIndex);

        uint256 proposalId = proposalQueue[proposalIndex];
        Proposal storage proposal = proposals[proposalId];

        require(proposal.flags[5], "must be a guild kick proposal");

        proposal.flags[1] = true; 

        (bool didPass,) = _didPass(proposalIndex);

        if (didPass) {
            proposal.flags[2] = true; 
            Member storage member = members[proposal.applicant];
            member.jailed = proposalIndex;


            member.loot = member.loot.add(member.shares);
            totalShares = totalShares.sub(member.shares);
            totalLoot = totalLoot.add(member.shares);
            member.shares = 0; 
        }

        proposedToKick[proposal.applicant] = false;

        _returnDeposit(proposal.sponsor);

        emit ProcessProposal(proposalIndex, proposalId, didPass);
    }

    function _didPass(uint256 proposalIndex) internal returns (bool didPass, bool emergencyProcessing) {
        Proposal memory proposal = proposals[proposalQueue[proposalIndex]];

        didPass = proposal.yesVotes > proposal.noVotes;


        emergencyProcessing = false;
        if (getCurrentPeriod() >= proposal.startingPeriod.add(votingPeriodLength).add(gracePeriodLength).add(emergencyProcessingWait)) {
            emergencyWarning = true;
            lastEmergencyProposalIndex = proposalIndex;
            emergencyProcessing = true;
            didPass = false;
        }


        if (emergencyWarning) {
            if (proposal.startingPeriod < proposals[proposalQueue[lastEmergencyProposalIndex]].startingPeriod.add(emergencyProcessingWait)) {
                didPass = false;
            }
        }


        if ((totalShares.add(totalLoot)).mul(dilutionBound) < proposal.maxTotalSharesAndLootAtYesVote) {
            didPass = false;
        }




        if (members[proposal.applicant].jailed != 0) {
            didPass = false;
        }

        return (didPass, emergencyProcessing);
    }

    function _validateProposalForProcessing(uint256 proposalIndex) internal view {
        require(proposalIndex < proposalQueue.length, "proposal does not exist");
        Proposal memory proposal = proposals[proposalQueue[proposalIndex]];

        require(getCurrentPeriod() >= proposal.startingPeriod.add(votingPeriodLength).add(gracePeriodLength), "proposal is not ready to be processed");
        require(proposal.flags[1] == false, "proposal has already been processed");
        require(proposalIndex == 0 || proposals[proposalQueue[proposalIndex.sub(1)]].flags[1], "previous proposal must be processed");
    }

    function _returnDeposit(address sponsor) internal {
        require(
            depositToken.transfer(msg.sender, processingReward),
            "failed to send processing reward to msg.sender"
        );

        require(
            depositToken.transfer(sponsor, proposalDeposit.sub(processingReward)),
            "failed to return proposal deposit to sponsor"
        );
    }

    function ragequit(uint256 sharesToBurn, uint256 lootToBurn) public nonReentrant onlyMember {
        _ragequit(msg.sender, sharesToBurn, lootToBurn, approvedTokens);
    }

    function safeRagequit(uint256 sharesToBurn, uint256 lootToBurn, IERC20[] memory tokenList) public nonReentrant onlyMember {

        for (uint256 i=0; i < tokenList.length; i++) {
            require(tokenWhitelist[address(tokenList[i])], "token must be whitelisted");

            if (i > 0) {
                require(tokenList[i] > tokenList[i - 1], "token list must be unique and in ascending order");
            }
        }

        _ragequit(msg.sender, sharesToBurn, lootToBurn, tokenList);
    }

    function _ragequit(address memberAddress, uint256 sharesToBurn, uint256 lootToBurn, IERC20[] memory tokenList) internal {
        uint256 initialTotalSharesAndLoot = totalShares.add(totalLoot);

        Member storage member = members[memberAddress];

        require(member.shares >= sharesToBurn, "insufficient shares");
        require(member.loot >= lootToBurn, "insufficient loot");

        require(canRagequit(member.highestIndexYesVote), "cannot ragequit until highest index proposal member voted YES on is processed");

        uint256 sharesAndLootToBurn = sharesToBurn.add(lootToBurn);


        member.shares = member.shares.sub(sharesToBurn);
        member.loot = member.loot.sub(lootToBurn);
        totalShares = totalShares.sub(sharesToBurn);
        totalLoot = totalLoot.sub(lootToBurn);


        require(
            guildBank.withdraw(memberAddress, sharesAndLootToBurn, initialTotalSharesAndLoot, tokenList),
            "withdrawal of tokens from guildBank failed"
        );

        emit Ragequit(msg.sender, sharesToBurn, lootToBurn);
    }

    function ragekick(address memberToKick) public nonReentrant {
        Member storage member = members[memberToKick];

        require(member.jailed != 0, "member must be in jail");
        require(member.loot > 0, "member must have some loot"); 
        require(canRagequit(member.highestIndexYesVote), "cannot ragequit until highest index proposal member voted YES on is processed");
        require(!canBailout(memberToKick), "bailoutWait has passed, member must be bailed out");

        _ragequit(memberToKick, 0, member.loot, approvedTokens);
    }

    function bailout(address memberToBail) public nonReentrant {
        Member storage member = members[memberToBail];

        require(member.jailed != 0, "member must be in jail");
        require(member.loot > 0, "member must have some loot"); 
        require(canBailout(memberToBail), "cannot bailout yet");

        members[summoner].loot = members[summoner].loot.add(member.loot);
        member.loot = 0;
    }

    function cancelProposal(uint256 proposalId) public nonReentrant {
        Proposal storage proposal = proposals[proposalId];
        require(!proposal.flags[0], "proposal has already been sponsored");
        require(!proposal.flags[3], "proposal has already been cancelled");
        require(msg.sender == proposal.proposer, "solely the proposer can cancel");

        proposal.flags[3] = true; 

        require(
            proposal.tributeToken.transfer(proposal.proposer, proposal.tributeOffered),
            "failed to return tribute to proposer"
        );

        emit CancelProposal(proposalId, msg.sender);
    }

    function updateDelegateKey(address newDelegateKey) public nonReentrant onlyShareholder {
        require(newDelegateKey != address(0), "newDelegateKey cannot be 0");


        if (newDelegateKey != msg.sender) {
            require(!members[newDelegateKey].exists, "cannot overwrite existing members");
            require(!members[memberAddressByDelegateKey[newDelegateKey]].exists, "cannot overwrite existing delegate keys");
        }

        Member storage member = members[msg.sender];
        memberAddressByDelegateKey[member.delegateKey] = address(0);
        memberAddressByDelegateKey[newDelegateKey] = msg.sender;
        member.delegateKey = newDelegateKey;

        emit UpdateDelegateKey(msg.sender, newDelegateKey);
    }



    function max(uint256 x, uint256 y) internal pure returns (uint256) {
        return x >= y ? x : y;
    }

    function getCurrentPeriod() public view returns (uint256) {
        return now.sub(summoningTime).div(periodDuration);
    }

    function getProposalQueueLength() public view returns (uint256) {
        return proposalQueue.length;
    }

    function getProposalFlags(uint256 proposalId) public view returns (bool[6] memory) {
        return proposals[proposalId].flags;
    }


    function canRagequit(uint256 highestIndexYesVote) public view returns (bool) {
        require(highestIndexYesVote < proposalQueue.length, "proposal does not exist");
        return proposals[proposalQueue[highestIndexYesVote]].flags[1];
    }

    function canBailout(address memberToBail) public view returns (bool) {
        Member memory member = members[memberToBail];



        uint256 bailoutWaitStartingPeriod = member.highestIndexYesVote > member.jailed
            ? proposals[proposalQueue[member.highestIndexYesVote]].startingPeriod
            : proposals[proposalQueue[member.jailed]].startingPeriod;


        return getCurrentPeriod() >= bailoutWaitStartingPeriod.add(votingPeriodLength).add(gracePeriodLength).add(bailoutWait);
    }

    function hasVotingPeriodExpired(uint256 startingPeriod) public view returns (bool) {
        return getCurrentPeriod() >= startingPeriod.add(votingPeriodLength);
    }

    function getMemberProposalVote(address memberAddress, uint256 proposalIndex) public view returns (Vote) {
        require(members[memberAddress].exists, "member does not exist");
        require(proposalIndex < proposalQueue.length, "proposal does not exist");
        return proposals[proposalQueue[proposalIndex]].votesByMember[memberAddress];
    }
}

pragma solidity ^0.7.3;

import "@openzeppelin/contracts-upgradeable/cryptography/ECDSAUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/utils/ContextUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/introspection/ERC165Upgradeable.sol";
import "@openzeppelin/contracts-upgradeable/token/ERC20/IERC20Upgradeable.sol";
import "@openzeppelin/contracts-upgradeable/token/ERC20/SafeERC20Upgradeable.sol";
import "@openzeppelin/contracts-upgradeable/token/ERC721/ERC721HolderUpgradeable.sol";

import "./interfaces/IRegistrar.sol";

contract StakingController is
  Initializable,
  ContextUpgradeable,
  ERC165Upgradeable,
  ERC721HolderUpgradeable
{
  using ECDSAUpgradeable for bytes32;
  using SafeERC20Upgradeable for IERC20Upgradeable;

  IERC20Upgradeable private infinity;
  IRegistrar private registrar;
  address private controller;

  mapping(bytes32 => bool) private approvedBids;

  event DomainBidPlaced(
    bytes32 indexed unsignedRequestHash,
    string indexed bidIPFSHash,
    bytes indexed signature
  );

  event DomainBidApproved(string indexed bidIdentifier);

  event DomainBidFulfilled(
    string indexed bidIdentifier,
    string name,
    address recoveredbidder,
    uint256 indexed id,
    uint256 indexed parentID
  );

  modifier authorizedOwner(uint256 domain) {
    require(registrar.domainExists(domain), "ZNS: Invalid Domain");
    require(
      registrar.ownerOf(domain) == _msgSender(),
      "ZNS: Not Authorized Owner"
    );
    _;
  }

  function initialize(IRegistrar _registrar, IERC20Upgradeable _infinity)
    public
    initializer
  {
    __ERC165_init();
    __Context_init();

    infinity = _infinity;
    registrar = _registrar;
    controller = address(this);
  }


  function placeDomainBid(
    uint256 parentId,
    bytes32 unsignedRequestHash,
    bytes memory signature,
    string memory bidIPFSHash
  ) external {
    require(registrar.domainExists(parentId), "ZNS: Invalid Domain");
    emit DomainBidPlaced(unsignedRequestHash, bidIPFSHash, signature);
  }



  function approveDomainBid(
    uint256 parentId,
    string memory bidIPFSHash,
    bytes memory signature
  ) external authorizedOwner(parentId) {
    bytes32 hashOfSig = keccak256(abi.encode(signature));
    approvedBids[hashOfSig] = true;
    emit DomainBidApproved(bidIPFSHash);
  }



  function fulfillDomainBid(
    uint256 parentId,
    uint256 bidAmount,
    uint256 royaltyAmount,
    string memory bidIPFSHash,
    string memory name,
    string memory metadata,
    bytes memory signature,
    bool lockOnCreation,
    address recipient
  ) external {
    bytes32 recoveredBidHash = createBid(
      parentId,
      bidAmount,
      bidIPFSHash,
      name
    );

    address recoveredBidder = recover(recoveredBidHash, signature);
    require(recipient == recoveredBidder, "ZNS: bid info doesnt match/exist");
    bytes32 hashOfSig = keccak256(abi.encode(signature));
    require(approvedBids[hashOfSig] == true, "ZNS: has been fullfilled");
    infinity.safeTransferFrom(recoveredBidder, controller, bidAmount);
    uint256 id = registrar.registerDomain(
      parentId,
      name,
      controller,
      recoveredBidder
    );
    registrar.setDomainMetadataUri(id, metadata);
    registrar.setDomainRoyaltyAmount(id, royaltyAmount);
    registrar.transferFrom(controller, recoveredBidder, id);
    if (lockOnCreation) {
      registrar.lockDomainMetadataForOwner(id);
    }
    approvedBids[hashOfSig] = false;
    emit DomainBidFulfilled(metadata, name, recoveredBidder, id, parentId);
  }


  function recover(bytes32 unsignedRequestHash, bytes memory signature)
    public
    pure
    returns (address)
  {
    return unsignedRequestHash.toEthSignedMessageHash().recover(signature);
  }


  function createBid(
    uint256 parentId,
    uint256 bidAmount,
    string memory bidIPFSHash,
    string memory name
  ) public pure returns (bytes32) {
    return keccak256(abi.encode(parentId, bidAmount, bidIPFSHash, name));
  }
}

pragma solidity 0.8.9;

import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/token/ERC20/IERC20Upgradeable.sol";
import "@openzeppelin/contracts-upgradeable/token/ERC20/extensions/IERC20MetadataUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/utils/ContextUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/security/PausableUpgradeable.sol";
import "./library/DateTime.sol";


contract AOC_BEP is Initializable, ContextUpgradeable, IERC20Upgradeable, IERC20MetadataUpgradeable, OwnableUpgradeable, PausableUpgradeable, UUPSUpgradeable {
    using DateTimeLibrary for uint;

    struct Level {
        uint256 start;
        uint256 end;
        uint256 percentage;
    }

    struct UserInfo {
        uint256 balance;
        uint256 level;
        uint256 year;
        uint256 month;
    }

    mapping (address => uint256) private _balances;
    mapping (address => mapping (address => uint256)) private _allowances;
    mapping (address => bool) public blacklisted;
    mapping (address => bool) public excludedFromRAMS;
    mapping (address => bool) public includedInLTAF;
    mapping(uint256 => Level) public levels;
    mapping(address => UserInfo) public userInfo;

    uint256 private _totalSupply;
    uint8 private constant _decimal = 18;
    string private constant _name = "Alpha Omega Coin";
    string private constant _symbol = "AOC BEP20";
    uint256 public ltafPercentage;


    event ExternalTokenTransfered(
        address from,
        address to,
        uint256 amount
    );

    event BNBFromContractTransferred(
        uint256 amount
    );

    event Blacklisted(
        string indexed action,
        address indexed to,
        uint256 at

    );

    event RemovedFromBlacklist(
        string indexed action,
        address indexed to,
        uint256 at
    );

    event IncludedInRAMS(
        address indexed account
    );

    event ExcludedFromRAMS(
        address indexed account
    );

    event IncludedInLTAF(
        address indexed account
    );

    event ExcludedFromLTAF(
        address indexed account
    );

    event LtafPercentageUpdated(
        uint256 percentage
    );


    function initialize() public initializer {

        _mint(_msgSender(), (1000 * 10**9 * 10**18)); 
        ltafPercentage = 50;

        addLevels(1, 1640995200, 1704153599, 20);
        addLevels(2, 1704153600, 1767311999, 15);
        addLevels(3, 1767312000, 1830383999, 10);
        addLevels(4, 1830384000, 0, 5);


        __Pausable_init_unchained();  
        __Ownable_init_unchained();  
        __Context_init_unchained();
    }

    function _authorizeUpgrade(address) internal override onlyOwner {}


    function name() external view virtual override returns (string memory) {
        return _name;
    }


    function symbol() external view virtual override returns (string memory) {
        return _symbol;
    }


    function decimals() external view virtual override returns (uint8) {
        return _decimal;
    }


    function totalSupply() external view virtual override returns (uint256) {
        return _totalSupply;
    }


    function balanceOf(address account) external view virtual override returns (uint256) {
        return _balances[account];
    }


    function transfer(address recipient, uint256 amount) external virtual override whenNotPaused returns (bool) {
        _transfer(_msgSender(), recipient, amount);
        return true;
    }


    function allowance(address owner, address spender) external view virtual override returns (uint256) {
        return _allowances[owner][spender];
    }


    function approve(address spender, uint256 amount) external virtual override whenNotPaused returns (bool) {
        _approve(_msgSender(), spender, amount);
        return true;
    }


    function transferFrom(address sender, address recipient, uint256 amount) external virtual override whenNotPaused returns (bool) {
        _transfer(sender, recipient, amount);

        uint256 currentAllowance = _allowances[sender][_msgSender()];
        require(currentAllowance >= amount, "BEP20: transfer amount exceeds allowance");
        _approve(sender, _msgSender(), currentAllowance - amount);

        return true;
    }


    function increaseAllowance(address spender, uint256 addedValue) external virtual whenNotPaused returns (bool) {
        _approve(_msgSender(), spender, _allowances[_msgSender()][spender] + addedValue);
        return true;
    }


    function decreaseAllowance(address spender, uint256 subtractedValue) external virtual whenNotPaused returns (bool) {
        uint256 currentAllowance = _allowances[_msgSender()][spender];
        require(currentAllowance >= subtractedValue, "BEP20: decreased allowance below zero");
        _approve(_msgSender(), spender, currentAllowance - subtractedValue);

        return true;
    }


    function burn(uint256 amount) external virtual onlyOwner whenNotPaused returns (bool) {
        _burn(_msgSender(), amount);
        return true;
    }


    function burnFrom(address account, uint256 amount) external virtual onlyOwner whenNotPaused {
        uint256 currentAllowance = _allowances[account][_msgSender()];
        require(currentAllowance >= amount, "BEP20: burn amount exceeds allowance");
        _approve(account, _msgSender(), currentAllowance - amount);
        _burn(account, amount);
    }

    function blacklistUser(address _address) external onlyOwner whenNotPaused {
        require(!blacklisted[_address], "User is already blacklisted");
        blacklisted[_address] = true;
        emit Blacklisted("Blacklisted", _address, block.timestamp);
	}

	function removeFromBlacklist(address _address) external onlyOwner whenNotPaused {
	    require(blacklisted[_address], "User is not in the blacklist");
	    blacklisted[_address] = false;
	    emit RemovedFromBlacklist("Removed", _address, block.timestamp);

	}

    function includeInRAMS(address account) external onlyOwner whenNotPaused {
        require(excludedFromRAMS[account], "User is already included");
        excludedFromRAMS[account] = false;
        emit IncludedInRAMS(account);
	}

    function excludeFromRAMS(address account) external onlyOwner whenNotPaused {
        require(!excludedFromRAMS[account], "User is already excluded");
        excludedFromRAMS[account] = true;
        emit ExcludedFromRAMS(account);
	}

    function includeInLTAF(address account) external onlyOwner whenNotPaused {
        require(!includedInLTAF[account], "User is already included");
        includedInLTAF[account] = true;
        emit IncludedInLTAF(account);
	}

    function excludedFromLTAF(address account) external onlyOwner whenNotPaused {
        require(includedInLTAF[account], "User is already excluded");
        includedInLTAF[account] = false;
        emit ExcludedFromLTAF(account);
	}

    function updateLtafPercentage(uint256 percentage) external onlyOwner whenNotPaused {
        require(percentage > 0, "Percentage must be greater than zero");
        ltafPercentage = percentage;
        emit LtafPercentageUpdated(ltafPercentage);
    }


    function pauseContract() external virtual onlyOwner {
        _pause();
    }


    function unPauseContract() external virtual onlyOwner {
        _unpause();
    }



    function withdrawBNBFromContract(address payable recipient, uint256 amount) external onlyOwner payable {
        require(recipient != address(0), "Address cant be zero address");
        require(amount <= address(this).balance, "withdrawBNBFromContract: withdraw amount exceeds BNB balance");              
        recipient.transfer(amount);        
        emit BNBFromContractTransferred(amount);
    }

    function withdrawToken(address _tokenContract, uint256 _amount) external onlyOwner {
        require(_tokenContract != address(0), "Address cant be zero address");

		require(_amount > 0, "amount cannot be 0");
        IERC20Upgradeable tokenContract = IERC20Upgradeable(_tokenContract);
        require(tokenContract.balanceOf(address(this)) > _amount, "withdrawToken: withdraw amount exceeds token balance");
		tokenContract.transfer(msg.sender, _amount);
        emit ExternalTokenTransfered(_tokenContract, msg.sender, _amount);
	}


    receive() external payable {}


    function _transfer(address sender, address recipient, uint256 amount) internal virtual {
        require(!blacklisted[sender] || !blacklisted[recipient], "AOC: Cant't transfer, User is blacklisted");
        require(sender != address(0), "AOC: transfer from the zero address");
        require(recipient != address(0), "AOC: transfer to the zero address");

        if(includedInLTAF[sender] || !excludedFromRAMS[sender]) {

            (uint256 year, uint256 month, uint256 day) = DateTimeLibrary.timestampToDate(block.timestamp);
            if(day == 1 || year != userInfo[sender].year || month != userInfo[sender].month || userInfo[sender].level == 0) updateUserInfo(sender, year, month);

            if(includedInLTAF[sender]) {

                require(amount <= ((userInfo[sender].balance * ltafPercentage) / 10**2), "BEP20: Amount is higher than LTAF percentage");
            } else if(!excludedFromRAMS[sender]) {

                if(userInfo[sender].level > 0) require(amount <= ((userInfo[sender].balance * levels[userInfo[sender].level].percentage) / 10**2), "BEP20: Amount is higher");
            }
        }

        uint256 senderBalance = _balances[sender];
        require(senderBalance >= amount, "BEP20: transfer amount exceeds balance");
        _balances[sender] = senderBalance - amount;
        _balances[recipient] += amount;

        emit Transfer(sender, recipient, amount);
    }

    function updateUserInfo(address account, uint256 year, uint256 month) internal {
        userInfo[account].balance = _balances[account];
        userInfo[account].year = year;
        userInfo[account].month = month;
        for(uint256 i = 1; i <= 4; i++) {
            if(i == 4) {
                userInfo[account].level = i;
                break;
            }
            if(block.timestamp >= levels[i].start && block.timestamp <= levels[i].end) {
                userInfo[account].level = i;
                break;
            }
        }
    }


    function _mint(address account, uint256 amount) internal virtual {
        require(account != address(0), "BEP20: mint to the zero address");
        _totalSupply += amount;
        _balances[account] += amount;
        emit Transfer(address(0), account, amount);
    }


    function _burn(address account, uint256 amount) internal virtual {
        require(account != address(0), "BEP20: burn from the zero address");
        uint256 accountBalance = _balances[account];
        require(accountBalance >= amount, "BEP20: burn amount exceeds balance");
        _balances[account] = accountBalance - amount;
        _totalSupply -= amount;

        emit Transfer(account, address(0), amount);
    }

    function _approve(address owner, address spender, uint256 amount) internal virtual {
        require(owner != address(0), "BEP20: approve from the zero address");
        require(spender != address(0), "BEP20: approve to the zero address");

        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }

    function addLevels(uint256 level, uint256 startDay, uint256 endDay, uint256 percentage) internal {
        levels[level] = Level({
            start: startDay,
            end: endDay,
            percentage: percentage
        });
    }

}

pragma solidity ^0.8.2;

import "./AniaStake.sol";

contract AniaLottery {

    AniaStake public tokenStaking;

    address public owner;
    uint public tierOne = 50000;
    uint public tierOneTicketValue = 1000;
    uint public tierTwo = 20000;
    uint public tierTwoTicketValue = 500;
    uint public tierThree = 10000;
    uint public tierThreeTicketValue = 250;
    uint internal decimals = 1000000000000000000;

    event eventAddUserToWhitelist(uint indexed id, address user, uint signupDate);
    event eventAddUserToLotteryWinners(uint indexed id, address user, uint reward, uint claimed);

    struct Project {
        uint id;
        string name;
        uint raiseGoal;
        uint endDate;
        address contractAddress;
        address billingAddress;
        uint firstPayoutInPercent;
        uint256 tokenPrice;
        bool draw;
    }
    mapping (uint => Project) projects;

    struct Whitelist {
        uint projectId;
        uint signupDate;
        address userAddress;
    }

    struct LotteryWinner {
        uint projectId;
        address userAddress;
        uint reward;
        bool claimed;
    }

    constructor(AniaStake _tokenStaking) {
        tokenStaking = _tokenStaking;
        owner = msg.sender;
    }

    modifier onlyAdmin {
        require(msg.sender == owner || admins[msg.sender]);
        _;
    }

    modifier onlyOwner {
        require(msg.sender == owner);
        _;
    }

    mapping(uint => uint) projectUserCount;
    mapping(uint => Whitelist[]) projectsWhitelist;
    mapping(uint => mapping(address => uint256)) projectUserIndex;
    mapping(uint => uint) projectStakeCap;
    mapping(uint => uint) lotteryWinnerCount;
    mapping(uint => LotteryWinner[]) lotteryWinners;
    mapping(uint => mapping(address => uint256)) projectWinnerIndex;
    mapping(uint => uint) projectRaisedAmount;
    mapping (address => bool) admins;

    mapping (address => bool) stableCoins;


    function setAdmin(address _admin, bool isAdmin) public onlyOwner {
        admins[_admin] = isAdmin;
    }

    function removeAdmin(address adminAddress) public onlyAdmin {
        _removeAdminFromAdmins(adminAddress);
    }

    function setStableCoin(address _address, bool isActive) public onlyOwner {
        stableCoins[_address] = isActive;
    }

    function createProject(uint projectId, string calldata projectName, uint raiseGoal, uint endDate, address contractAddress, address billingAddress, uint firstPayoutInPercent, uint256 tokenPrice) external onlyAdmin {
        require(!_checkProjectExistById(projectId), "Project with this ID exist.");

        Project memory newProject = Project(projectId, projectName, raiseGoal, endDate, contractAddress, billingAddress, firstPayoutInPercent, tokenPrice, false);

        projects[projectId] = newProject;
    }

    function updateProject(uint projectId, string calldata projectName, uint raiseGoal, uint endDate, address contractAddress, address billingAddress, uint firstPayoutInPercent, uint256 tokenPrice) external onlyAdmin {


        require(projects[projectId].id == projectId, "Project with this ID not exist.");

        projects[projectId].name = projectName;
        projects[projectId].raiseGoal = raiseGoal;
        projects[projectId].endDate = endDate;
        projects[projectId].contractAddress = contractAddress;
        projects[projectId].billingAddress = billingAddress;
        projects[projectId].firstPayoutInPercent= firstPayoutInPercent;
        projects[projectId].tokenPrice = tokenPrice;
    }

    function removeProject(uint projectId) external onlyAdmin {
        _removeWhitelist(projectId);
        _removeProject(projectId);
    }



    function withdraw() public payable onlyOwner {
        payable (msg.sender).transfer(address(this).balance);
    }

    function withdrawTokens(uint projectId, address recipient) public onlyAdmin {
        address contractAddress = projects[projectId].contractAddress;

        IERC20 token = IERC20(contractAddress);
        token.transfer(recipient, token.balanceOf(address(this)));
    }


    function addUsersToWhitelist(uint projectId, address[] calldata users, bool checkEndDate) external onlyAdmin {

        if(checkEndDate){
            require(_checkOpenProject(projectId), "Project is close.");
        }

        require(!projects[projectId].draw, "The lottery has been launched and project is completed close.");
        for (uint i; i < users.length; i++) {
            if(!_checkUserExistInProject(projectId, users[i])){
                projectsWhitelist[projectId].push(
                    Whitelist({
                        projectId: projectId,
                        userAddress: users[i],
                        signupDate: block.timestamp
                    })
                );
                projectStakeCap[projectId] += getUserTicketValue(users[i]);
                uint256 index = projectsWhitelist[projectId].length - 1;
                projectUserIndex[projectId][users[i]] = index;
                projectUserCount[projectId]++;
                emit eventAddUserToWhitelist(projectId, users[i], block.timestamp);
            }
        }
    }


    function removeUsersFromWhitelist(uint projectId, address[] calldata users) external onlyAdmin {
        for (uint i; i < users.length; i++) {
            _removeUserFromProject(projectId, users[i]);
        }
    }

    function getUserTicketValue(address _address) public view returns (uint256) {
        uint256 userStake = tokenStaking.hasStakeWithRewards(_address);
        if(userStake >= tierOne * decimals){
            return tierOneTicketValue;
        } else if (userStake >= tierTwo * decimals){
            return tierTwoTicketValue;
        } else if (userStake >= tierThree * decimals){
            return tierThreeTicketValue;
        }
        return 0;
    }

    function getProjectStakeCap(uint projectId) public view returns(uint256) {
        return projectStakeCap[projectId];
    }

    function getProjectRaisedAmount(uint projectId) public view returns(uint256) {
        return projectRaisedAmount[projectId];
    }

    function lotteryDraw(uint projectId, address[] calldata users) external onlyAdmin {
        require(_checkProjectExistById(projectId), "Project with this ID does not exist.");
        require(!_checkOpenProject(projectId), "Project is open and should be closed.");

        require(!projects[projectId].draw, "The lottery has been already drawn.");

        for (uint i; i < users.length; i++) {
            address user = users[i];
            if(_checkUserExistInProject(projectId, user) && !_checkUserIsProjectWinner(projectId, user)){
                uint reward = getUserTicketValue(user);
                if (reward > 0) {
                    lotteryWinners[projectId].push(
                        LotteryWinner({
                            projectId: projectId,
                            userAddress: user,
                            reward: reward,
                            claimed: false
                        })
                    );
                    uint256 index = lotteryWinners[projectId].length - 1;
                    projectWinnerIndex[projectId][user] = index;
                    lotteryWinnerCount[projectId]++;
                    emit eventAddUserToLotteryWinners(projectId, user, reward, 0);
                }
            }
        }


        projects[projectId].draw = true;
    }

    function getProject(uint projectId) external view returns (Project memory) {
        return projects[projectId];
    }

    function getUserCount(uint projectId) external view returns (uint) {
        return projectUserCount[projectId];
    }

    function getProjectUser(uint projectId, address userAddress) public view returns (Whitelist memory) {
        uint256 index = projectUserIndex[projectId][userAddress];
        require(projectsWhitelist[projectId][index].userAddress == userAddress, "User not found");
        return projectsWhitelist[projectId][index];
    }

    function getLotteryWinner(uint projectId, address userAddress) public view returns (LotteryWinner memory) {
        uint256 index = projectWinnerIndex[projectId][userAddress];
        require(lotteryWinners[projectId][index].userAddress == userAddress, "Winner not found");
        return lotteryWinners[projectId][index];
    }

    function getLotteryWinnerCount(uint projectId) external view returns (uint) {
        return lotteryWinnerCount[projectId];
    }

    function setLotteryWinnerClaimedStatus(uint projectId, address userAddress) internal {
        uint256 index = projectWinnerIndex[projectId][userAddress];
        require(lotteryWinners[projectId][index].userAddress == userAddress, "User not found");
        lotteryWinners[projectId][index].claimed = true;
    }


    function changeTierOne(uint _value) external onlyAdmin {
        require(_value > 0, "Tier value has to be more than 0");
        require(_value > tierTwo, "Tier value has to be more than Tier Two");
        require(_value > tierThree, "Tier value has to be more than Tier Three");
        tierOne = _value;
    }
    function changeTierTwo(uint _value) external onlyAdmin {
        require(_value > 0, "Tier value has to be more than 0");
        require(_value < tierOne, "Tier value has to be less than Tier One");
        require(_value > tierThree, "Tier value has to be more than Tier Three");
        tierTwo = _value;
    }
    function changeTierThree(uint _value) external onlyAdmin {
        require(_value > 0, "Tier value has to be more than 0");
        require(_value < tierOne, "Tier value has to be less than Tier One");
        require(_value < tierTwo, "Tier value has to be less than Tier Two");
        tierThree = _value;
    }
    function changeTierOneTicketValue(uint _value) external onlyAdmin {
        require(_value > 0, "Tier Ticket value has to be more than 0");
        require(_value > tierTwoTicketValue, "Tier Ticket value has to be more than Tier Two");
        require(_value > tierThreeTicketValue, "Tier Ticket value has to be more than Tier Three");
        tierOneTicketValue = _value;
    }
    function changeTierTwoTicketValue(uint _value) external onlyAdmin {
        require(_value > 0, "Tier Ticket value has to be more than 0");
        require(_value < tierOneTicketValue, "Tier Ticket value has to be less than Tier One");
        require(_value > tierThreeTicketValue, "Tier Ticket value has to be more than Tier Three");
        tierTwoTicketValue = _value;
    }
    function changeTierThreeTicketValue(uint _value) external onlyAdmin {
        require(_value > 0, "Tier Ticket value has to be more than 0");
        require(_value < tierOneTicketValue, "Tier Ticket value has to be less than Tier One");
        require(_value < tierTwoTicketValue, "Tier Ticket value has to be less than Tier Two");
        tierThreeTicketValue = _value;
    }


    function signUpToWhitelist(uint projectId) external {

        require(_checkOpenProject(projectId), "Project is close.");

        require(!_checkUserExistInProject(projectId, msg.sender), "User is already in whitelist.");
        projectsWhitelist[projectId].push(
            Whitelist({
                projectId: projectId,
                userAddress: msg.sender,
                signupDate: block.timestamp
            })
        );
        projectStakeCap[projectId] += getUserTicketValue(msg.sender);
        uint256 index = projectsWhitelist[projectId].length - 1;
        projectUserIndex[projectId][msg.sender] = index;
        projectUserCount[projectId]++;
        emit eventAddUserToWhitelist(projectId, msg.sender, block.timestamp);
    }

    function logoutFromWhitelist(uint projectId) external {
        _removeUserFromProject(projectId, msg.sender);
    }


    function isProjectOpen(uint projectId) external view returns (bool){
        return _checkOpenProject(projectId);
    }


    function isUserInWhitelist(uint projectId) external view returns (bool) {
        return _checkUserExistInProject(projectId, msg.sender);
    }

    function checkBuy(uint projectId, uint256 tokensToBuy) public view returns (bool) {

        require(projectId > 0, "ProjectId must be selected");
        require(_checkProjectExistById(projectId), "Project with this ID does not exist.");


        address contractAddress = projects[projectId].contractAddress;


        uint256 availableTokens = anyoneTokenBalance(contractAddress, address(this));
        require(availableTokens > 0, "Insufficient tokens in contract");


        require(tokensToBuy > 0, "Insufficient tokens to send");
        require(tokensToBuy < availableTokens, "Insufficient tokens in contract to send");


        LotteryWinner memory winner = getLotteryWinner(projectId, msg.sender);
        require(!winner.claimed, "User already claimed the reward");

        return true;
    }

    function buy(uint projectId, uint pay, address tokenForPayContractAddress) external {

        require(stableCoins[tokenForPayContractAddress], "This Token is not available for payment");


        require(pay > 0, "You need to send some ether");
        require(getUserTicketValue(msg.sender) == pay, "You need to pay the exact tier value before claiming the reward");

        uint256 tokensToBuy = decimals * (pay * decimals) / projects[projectId].tokenPrice * projects[projectId].firstPayoutInPercent / 100;


        checkBuy(projectId, tokensToBuy);

        address billingAddress = projects[projectId].billingAddress;
        address contractAddress = projects[projectId].contractAddress;
        require(billingAddress != contractAddress, "Billing Address must be different as Contract Address");


        IERC20 token = IERC20(contractAddress);

        token.transfer(msg.sender, tokensToBuy);


        IERC20 stableCoin = IERC20(tokenForPayContractAddress);
        stableCoin.transferFrom(msg.sender, billingAddress, pay * decimals);


        setLotteryWinnerClaimedStatus(projectId, msg.sender);
        projectRaisedAmount[projectId] += pay;
    }


    function anyoneTokenBalance(address tokenContractAddress, address userAddress) public view returns(uint) {
        IERC20 token = IERC20(tokenContractAddress);
        return token.balanceOf(userAddress);
    }


    function _checkProjectExistById(uint projectId) internal view returns (bool) {
        if(projects[projectId].id > 0){
            return true;
        }
        return false;
    }

    function _checkUserExistInProject(uint projectId, address userAddress) internal view returns (bool) {
        if (projectsWhitelist[projectId].length == 0) {
            return false;
        }

        uint256 index = projectUserIndex[projectId][userAddress];
        if (projectsWhitelist[projectId][index].userAddress == userAddress) {
            return true;
        }
        return false;
    }

    function _checkUserIsProjectWinner(uint projectId, address userAddress) internal view returns (bool) {
        if (lotteryWinners[projectId].length == 0) {
            return false;
        }

        uint256 index = projectWinnerIndex[projectId][userAddress];
        if (lotteryWinners[projectId][index].userAddress == userAddress) {
            return true;
        }
        return false;
    }

    function _checkOpenProject(uint projectId) internal view returns (bool) {
        return projects[projectId].id > 0 && projects[projectId].endDate > block.timestamp;
    }

    function _removeUserFromProject(uint256 projectId, address userAddress) internal {
        uint256 index = projectUserIndex[projectId][userAddress];
        if (projectsWhitelist[projectId][index].userAddress == userAddress) {
            delete projectUserIndex[projectId][userAddress];
            projectStakeCap[projectId] -= getUserTicketValue(projectsWhitelist[projectId][index].userAddress);
            delete projectsWhitelist[projectId][index];
            projectUserCount[projectId]--;
        }
    }

    function _removeAdminFromAdmins(address adminAddress) internal {
        delete admins[adminAddress];
    }

    function _removeWhitelist(uint projectId) internal {
        projectStakeCap[projectId] = 0;
        projectRaisedAmount[projectId] = 0;
        delete projectsWhitelist[projectId];
    }

    function _removeProject(uint projectId) internal {
        projectUserCount[projectId] = 0;
        lotteryWinnerCount[projectId] = 0;
        delete projects[projectId];
    }

}

pragma solidity ^0.8.0;

import "@openzeppelin/contracts/access/Ownable.sol";


struct CENNZnetEventProof {

    uint256 eventId;

    uint32 validatorSetId;



    uint8[] v;

    bytes32[] r;

    bytes32[] s;
}


contract CENNZnetBridge is Ownable {



    mapping(uint => address[]) public validators;

    uint32 public activeValidatorSetId;



    mapping(uint => bool) public eventIds;


    uint public verificationFee = 1e15;

    uint public thresholdPercent = 61;

    uint public proofTTL = 3;

    bool public active = true;

    event SetValidators(address[], uint reward, uint32 validatorSetId);











    function verifyMessage(bytes memory message, CENNZnetEventProof memory proof) payable external {
        require(active, "bridge inactive");
        uint256 eventId = proof.eventId;
        require(!eventIds[eventId], "eventId replayed");
        require(msg.value >= verificationFee || msg.sender == address(this), "must supply verification fee");
        uint32 validatorSetId = proof.validatorSetId;
        require(validatorSetId <= activeValidatorSetId, "future validator set");
        require(activeValidatorSetId - validatorSetId <= proofTTL, "expired proof");

        address[] memory _validators = validators[validatorSetId];


        require(_validators.length > 0, "invalid validator set");

        bytes32 digest = keccak256(message);
        uint acceptanceTreshold = (_validators.length * thresholdPercent / 100);
        uint witnessCount;
        bytes32 ommited;

        for (uint i; i < _validators.length; i++) {

            if(proof.r[i] != ommited) {

                require(_validators[i] == ecrecover(digest, proof.v[i], proof.r[i], proof.s[i]), "signature invalid");
                witnessCount += 1;

                if(witnessCount >= acceptanceTreshold) {
                    break;
                }
            }
        }

        require(witnessCount >= acceptanceTreshold, "not enough signatures");
        eventIds[eventId] = true;
    }








    function setValidators(
        address[] memory newValidators,
        uint32 newValidatorSetId,
        CENNZnetEventProof memory proof
    ) external payable {
        require(newValidators.length > 0, "empty validator set");
        require(newValidatorSetId > activeValidatorSetId , "validator set id replayed");

        bytes memory message = abi.encode(newValidators, newValidatorSetId, proof.validatorSetId, proof.eventId);
        this.verifyMessage(message, proof);


        validators[newValidatorSetId] = newValidators;
        activeValidatorSetId = newValidatorSetId;


        uint reward = address(this).balance;
        (bool sent, ) = msg.sender.call{value: reward}("");
        require(sent, "Failed to send Ether");

        emit SetValidators(newValidators, reward, newValidatorSetId);
    }




    function forceActiveValidatorSet(address[] memory _validators, uint32 validatorSetId) external onlyOwner {
        require(_validators.length > 0, "empty validator set");
        require(validatorSetId >= activeValidatorSetId, "set is historic");
        validators[validatorSetId] = _validators;
        activeValidatorSetId = validatorSetId;
    }



    function forceHistoricValidatorSet(address[] memory _validators, uint32 validatorSetId) external onlyOwner {
        require(_validators.length > 0, "empty validator set");
        require(validatorSetId + proofTTL > activeValidatorSetId, "set is inactive");
        validators[validatorSetId] = _validators;
    }


    function setProofTTL(uint newTTL) external onlyOwner {
        proofTTL = newTTL;
    }


    function setVerificationFee(uint newFee) external onlyOwner {
        verificationFee = newFee;
    }


    function setThreshold(uint newThresholdPercent) external onlyOwner {
        thresholdPercent = newThresholdPercent;
    }


    function setActive(bool active_) external onlyOwner {
        active = active_;
    }
}

pragma solidity ^0.8.4;





import "@openzeppelin/contracts/token/ERC1155/presets/ERC1155PresetMinterPauser.sol";
import "@openzeppelin/contracts/token/ERC20/presets/ERC20PresetMinterPauser.sol";
import "hardhat/console.sol";

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

contract IDO is Ownable {
    IERC20 public GZT;

    bool public idoStatus;

    uint256 public idoStart;
    uint256 public idoFinish;

    uint256 public cooldownToClaim;
    uint256 public allowedAmountToClaim;

    address[] public _allowedTokens;

    struct WhitelistInstance {
        uint256 maxAmountToClaim;
        bool isWhitelisted;
    }

    struct IDOParticipant {
        uint256 start;
        uint256 amountToClaim;
        uint256 claimedLastTime;
        uint256 claimedAmount;
        bool hasClaimed;
    }

    mapping(address => WhitelistInstance) public whitelist;
    mapping(address => IDOParticipant) public pool;

    mapping(IERC20 => bool) public allowedTokens;
    mapping(IERC20 => uint256[2]) public rates; 

    event UserIsWhitelisted(address indexed user, uint256 indexed amount);
    event NewIDOParticipant(IERC20 indexed token, address indexed user, uint256 amount);

    constructor(IERC20 _IDO_TOKEN) {
        GZT = _IDO_TOKEN;
    }

    function participate(uint256 amountToSpent, IERC20 token) external {
        uint256[2] memory rate = rates[token];
        uint256 amountToClaim = ((amountToSpent * rate[0]) / rate[1]);

        require(idoStatus, "The IDO is not started!");
        require(block.timestamp < idoFinish, "The IDO is already finished!");
        require(pool[msg.sender].start == 0, "You're already participating in IDO");
        require(token.balanceOf(msg.sender) >= amountToSpent, "You don't have enough money!");
        require(whitelist[msg.sender].maxAmountToClaim >= amountToClaim, "You're not permited to claim this amount!");
        require(whitelist[msg.sender].isWhitelisted, "You're not whitelisted");

