pragma solidity ^0.6.0;

library SafeMath {
    function add(uint a, uint b) internal pure returns (uint c) {
        c = a + b;
        require(c >= a);
    }

    function sub(uint a, uint b) internal pure returns (uint c) {
        require(b <= a);
        c = a - b;
    }

    function mul(uint a, uint b) internal pure returns (uint c) {
        c = a * b;
        require(a == 0 || c / a == b);
    }

    function div(uint a, uint b) internal pure returns (uint c) {
        require(b > 0);
        c = a / b;
    }
}

interface IERC20 {
    function transfer(address to, uint tokens) external returns (bool success);
    function transferFrom(address from, address to, uint tokens) external returns (bool success);
    function balanceOf(address tokenOwner) external view returns (uint balance);
    function approve(address spender, uint tokens) external returns (bool success);
    function allowance(address tokenOwner, address spender) external view returns (uint remaining);
    function totalSupply() external view returns (uint);

    event Transfer(address indexed from, address indexed to, uint tokens);
    event Approval(address indexed tokenOwner, address indexed spender, uint tokens);
}

contract ERC20 is IERC20 {

    using SafeMath for uint;

    string public name;
    string public symbol;
    uint private tokenTotalSupply;
    mapping(address => uint) private balances;
    mapping(address => mapping(address => uint)) private allowed;

    constructor(string memory _name, string memory _symbol, uint _amount) public {
        name = _name;
        symbol = _symbol; 
        _mint(msg.sender, _amount);
    }

    modifier canApprove(address spender, uint value) {
        require(spender != msg.sender, 'Cannot approve self');
        require(spender != address(0x0), 'Cannot approve a zero address');
        require(balances[msg.sender] >= value, 'Cannot approve more than available balance');
        _;
    }

    function transfer(address to, uint value) public override returns(bool) {
        require(balances[msg.sender] >= value);
        balances[msg.sender] = balances[msg.sender].sub(value);
        balances[to] = balances[to].add(value);
        emit Transfer(msg.sender, to, value);
        return true;
    }

    function transferFrom(address from, address to, uint value) public override returns(bool) {
        uint allowance = allowed[from][msg.sender];
        require(balances[from] >= value && allowance >= value);
        allowed[from][msg.sender] = allowed[from][msg.sender].sub(value);
        balances[from] = balances[from].sub(value);
        balances[to] = balances[to].add(value);
        emit Transfer(from, to, value);
        return true;
    }

    function approve(address spender, uint value) external override canApprove(spender, value) returns(bool) {
        allowed[msg.sender][spender] = value;
        emit Approval(msg.sender, spender, value);
        return true;
    }

    function allowance(address owner, address spender) public override view returns(uint) {
        return allowed[owner][spender];
    }

    function balanceOf(address owner) public override view returns(uint) {
        return balances[owner];
    }

    function totalSupply() external override view returns(uint) {
        return tokenTotalSupply;
    }

    function _mint(address _account, uint _amount) internal {
        require(_account != address(0x0), "ERC20: mint to the zero address");
        tokenTotalSupply = tokenTotalSupply.add(_amount);
        balances[_account] = balances[_account].add(_amount);
        emit Transfer(address(0), _account, _amount);
    }
}

pragma solidity ^0.6.0;

import '@openzeppelin/contracts/math/SafeMath.sol';

import '@openzeppelin/contracts/token/ERC20/IERC20.sol';

import '@openzeppelin/contracts/access/Ownable.sol';

contract LeadStake is Ownable {


    using SafeMath for uint;


    address public lead;

    uint public totalStaked;

    uint public stakingTaxRate;                     

    uint public registrationTax;

    uint8 public dailyROI;                         

    uint public unstakingTaxRate;                   

    uint public minimumStakeValue;

    uint public referralTaxAllocation;

    uint index;

    bool active = true;

    mapping(uint => address) public userIndex;

    mapping(address => uint) public stakes;

    mapping(address => uint) public stakeRewards;

    mapping(address => uint) public referralCount;

    mapping(address => uint) public referralRewards;

    mapping(address => uint) public lastClock;

    mapping(address => bool) public registered;


    event OnWithdrawal(address sender, uint amount);
    event OnStake(address sender, uint amount, uint tax);
    event OnUnstake(address sender, uint amount, uint tax);
    event OnDeposit(address sender, uint amount, uint time);
    event OnRegisterAndStake(address stakeholder, uint amount, uint totalTax , address _referrer);


    constructor(
        address _token,
        uint8 _stakingTaxRate, 
        uint8 _unstakingTaxRate,
        uint8 _dailyROI,
        uint _registrationTax,
        uint _referralTaxAllocation,
        uint _minimumStakeValue) public {


        lead = _token;
        stakingTaxRate = _stakingTaxRate;
        unstakingTaxRate = _unstakingTaxRate;
        dailyROI = _dailyROI;
        registrationTax = _registrationTax;
        referralTaxAllocation = _referralTaxAllocation;
        minimumStakeValue = _minimumStakeValue;
    }


    modifier onlyRegistered() {
        require(registered[msg.sender] == true, "Staker must be registered");
        _;
    }


    modifier onlyUnregistered() {
        require(registered[msg.sender] == false, "Staker is already registered");
        _;
    }


    modifier whenActive() {
        require(active == true, "Smart contract is curently inactive");
        _;
    }


    function registerAndStake(uint _amount, address _referrer) external onlyUnregistered() whenActive() {

        require(msg.sender != _referrer, "Cannot refer self");

        require(registered[_referrer] || address(0x0) == _referrer, "Referrer must be registered");

        require(IERC20(lead).balanceOf(msg.sender) >= _amount, "Must have enough balance to stake");

        require(IERC20(lead).transferFrom(msg.sender, address(this), _amount), "Stake failed due to failed amount transfer.");

        require(_amount >= registrationTax.add(minimumStakeValue), "Must send at least enough LEAD to pay registration fee.");

        uint referralBonus = (registrationTax.mul(referralTaxAllocation)).div(100);

        uint finalAmount = _amount.sub(registrationTax);

        uint stakingTax = (stakingTaxRate.mul(finalAmount)).div(1000);

        if(_referrer != address(0x0)) {

            referralCount[_referrer]++;

            referralRewards[_referrer] = referralRewards[_referrer].add(referralBonus);
        } 

        stakes[msg.sender] = stakes[msg.sender].add(finalAmount).sub(stakingTax);

        totalStaked = totalStaked.add(finalAmount).sub(stakingTax);

        registered[msg.sender] = true;
        userIndex[index] = msg.sender;
        index++;

        lastClock[msg.sender] = now;

        emit OnRegisterAndStake(msg.sender, _amount, registrationTax.add(stakingTax), _referrer);
    }


    function calculateEarnings(address _stakeholder) public view returns(uint) {

        uint activeDays = (now.sub(lastClock[_stakeholder])).div(86400);

        return (stakes[_stakeholder].mul(dailyROI).mul(activeDays)).div(10000);
    }


    function stake(uint _amount) external onlyRegistered() whenActive() {

        require(_amount >= minimumStakeValue, "Amount is below minimum stake value.");

        require(IERC20(lead).balanceOf(msg.sender) >= _amount, "Must have enough balance to stake");

        require(IERC20(lead).transferFrom(msg.sender, address(this), _amount), "Stake failed due to failed amount transfer.");

        uint stakingTax = (stakingTaxRate.mul(_amount)).div(1000);

        uint afterTax = _amount.sub(stakingTax);

        totalStaked = totalStaked.add(afterTax);

        stakeRewards[msg.sender] = stakeRewards[msg.sender].add(calculateEarnings(msg.sender));

        uint remainder = (now.sub(lastClock[msg.sender])).mod(86400);

        lastClock[msg.sender] = now.sub(remainder);

        stakes[msg.sender] = stakes[msg.sender].add(afterTax);

        emit OnStake(msg.sender, afterTax, stakingTax);
    }



    function unstake(uint _amount) external onlyRegistered() {

        require(_amount <= stakes[msg.sender] && _amount > 0, 'Insufficient balance to unstake');

        uint unstakingTax = (unstakingTaxRate.mul(_amount)).div(1000);

        uint afterTax = _amount.sub(unstakingTax);

        uint unstakePlusAllEarnings = stakeRewards[msg.sender].add(referralRewards[msg.sender]).add(afterTax).add(calculateEarnings(msg.sender));

        IERC20(lead).transfer(msg.sender, unstakePlusAllEarnings);

        stakes[msg.sender] = stakes[msg.sender].sub(_amount);

        stakeRewards[msg.sender] = 0;

        referralRewards[msg.sender] = 0;

        referralCount[msg.sender] = 0;

        uint remainder = (now.sub(lastClock[msg.sender])).mod(86400);

        lastClock[msg.sender] = now.sub(remainder);

        totalStaked = totalStaked.sub(_amount);

        if(stakes[msg.sender] == 0) {

            _removeStakeholder(msg.sender);
        }

        emit OnUnstake(msg.sender, _amount, unstakingTax);
    }


    function isStakeholder(address _address) public view returns(bool, uint) {

        for (uint i = 0; i < index; i += 1){

            if (_address == userIndex[i]) {

                return (true, i);
            }
        }

        return (false, 0);
    }


    function _removeStakeholder(address _stakeholder) internal {

        registered[msg.sender] = false;

        (bool _isStakeholder, uint i) = isStakeholder(_stakeholder);
        if(_isStakeholder){
            delete userIndex[i];
        }
    }


    function withdrawEarnings() external onlyRegistered() whenActive() {

        uint totalReward = referralRewards[msg.sender].add(stakeRewards[msg.sender]).add(calculateEarnings(msg.sender));

        require(totalReward > 0, 'No reward to withdraw'); 

        IERC20(lead).transfer(msg.sender, totalReward);

        stakeRewards[msg.sender] = 0;

        referralRewards[msg.sender] = 0;

        referralCount[msg.sender] = 0;

        uint remainder = (now.sub(lastClock[msg.sender])).mod(86400);

        lastClock[msg.sender] = now.sub(remainder);

        emit OnWithdrawal(msg.sender, totalReward);
    }

    function changeActiveStatus() external onlyOwner() {
        if(active = true) {
            active == false;
        } else {
            active == true;
        }
    }


    function setStakingTaxRate(uint8 _stakingTaxRate) external onlyOwner() {
        stakingTaxRate = _stakingTaxRate;
    }


    function setUnstakingTaxRate(uint8 _unstakingTaxRate) external onlyOwner() {
        unstakingTaxRate = _unstakingTaxRate;
    }


    function setDailyROI(uint8 _dailyROI) external onlyOwner() {
        for(uint i = 0; i < index; i++){

            stakeRewards[userIndex[i]] = stakeRewards[userIndex[i]].add(calculateEarnings(userIndex[i]));

            uint remainder = (now.sub(lastClock[userIndex[i]])).mod(86400);

            lastClock[userIndex[i]] = now.sub(remainder);
        }
        dailyROI = _dailyROI;
    }


    function setRegistrationTax(uint _registrationTax) external onlyOwner() {
        registrationTax = _registrationTax;
    }


    function setReferralTaxAllocation(uint _referralTaxAllocation) external onlyOwner() {
        referralTaxAllocation = _referralTaxAllocation;
    }


    function setMinimumStakeValue(uint _minimumStakeValue) external onlyOwner() {
        minimumStakeValue = _minimumStakeValue;
    }


    function adminWithdraw(address _address, uint _amount) external onlyOwner {

        require(IERC20(lead).balanceOf(address(this)) >= _amount, 'Insufficient LEAD balance in smart contract');

        IERC20(lead).transfer(_address, _amount);

        emit OnWithdrawal(_address, _amount);
    }


    function supplyPool() external onlyOwner() {

        uint totalClaimable;

        for(uint i = 0; i < index; i++){

            totalClaimable = stakeRewards[userIndex[i]].add(referralRewards[userIndex[i]]).add(stakes[userIndex[i]]).add(calculateEarnings(userIndex[i]));
        }

        require(totalClaimable > IERC20(lead).balanceOf(address(this)), 'Still have enough pool reserve');

        uint difference = totalClaimable.sub(IERC20(lead).balanceOf(address(this)));

        require(IERC20(lead).balanceOf(msg.sender) >= difference, 'Insufficient LEAD balance in owner wallet');

        IERC20(lead).transferFrom(msg.sender, address(this), difference);

        emit OnDeposit(msg.sender, difference, now);
    }
}

pragma solidity ^0.6.0;

library SafeMath {
    function add(uint a, uint b) internal pure returns (uint c) {
        c = a + b;
        require(c >= a);
    }

    function sub(uint a, uint b) internal pure returns (uint c) {
        require(b <= a);
        c = a - b;
    }

    function mul(uint a, uint b) internal pure returns (uint c) {
        c = a * b;
        require(a == 0 || c / a == b);
    }

    function div(uint a, uint b) internal pure returns (uint c) {
        require(b > 0);
        c = a / b;
    }
}

interface IERC20 {
    function transfer(address to, uint tokens) external returns (bool success);
    function transferFrom(address from, address to, uint tokens) external returns (bool success);
    function balanceOf(address tokenOwner) external view returns (uint balance);
    function approve(address spender, uint tokens) external returns (bool success);
    function allowance(address tokenOwner, address spender) external view returns (uint remaining);
    function totalSupply() external view returns (uint);

    event Transfer(address indexed from, address indexed to, uint tokens);
    event Approval(address indexed tokenOwner, address indexed spender, uint tokens);
}

contract ERC20 is IERC20 {

    using SafeMath for uint;

    string public name;
    string public symbol;
    uint private tokenTotalSupply;
    mapping(address => uint) private balances;
    mapping(address => mapping(address => uint)) private allowed;

    constructor(string memory _name, string memory _symbol, uint _amount) public {
        name = _name;
        symbol = _symbol; 
        _mint(msg.sender, _amount);
    }

    modifier canApprove(address spender, uint value) {
        require(spender != msg.sender, 'Cannot approve self');
        require(spender != address(0x0), 'Cannot approve a zero address');
        require(balances[msg.sender] >= value, 'Cannot approve more than available balance');
        _;
    }

    function transfer(address to, uint value) public override returns(bool) {
        require(balances[msg.sender] >= value);
        balances[msg.sender] = balances[msg.sender].sub(value);
        balances[to] = balances[to].add(value);
        emit Transfer(msg.sender, to, value);
        return true;
    }

    function transferFrom(address from, address to, uint value) public override returns(bool) {
        uint allowance = allowed[from][msg.sender];
        require(balances[from] >= value && allowance >= value);
        allowed[from][msg.sender] = allowed[from][msg.sender].sub(value);
        balances[from] = balances[from].sub(value);
        balances[to] = balances[to].add(value);
        emit Transfer(from, to, value);
        return true;
    }

    function approve(address spender, uint value) external override canApprove(spender, value) returns(bool) {
        allowed[msg.sender][spender] = value;
        emit Approval(msg.sender, spender, value);
        return true;
    }

    function allowance(address owner, address spender) public override view returns(uint) {
        return allowed[owner][spender];
    }

    function balanceOf(address owner) public override view returns(uint) {
        return balances[owner];
    }

    function totalSupply() external override view returns(uint) {
        return tokenTotalSupply;
    }

    function _mint(address _account, uint _amount) internal {
        require(_account != address(0x0), "ERC20: mint to the zero address");
        tokenTotalSupply = tokenTotalSupply.add(_amount);
        balances[_account] = balances[_account].add(_amount);
        emit Transfer(address(0), _account, _amount);
    }
}

pragma solidity ^0.6.0;

import '@openzeppelin/contracts/math/SafeMath.sol';

import '@openzeppelin/contracts/token/ERC20/IERC20.sol';

import '@openzeppelin/contracts/access/Ownable.sol';

contract LeadStake is Ownable {


    using SafeMath for uint;


    address public lead;

    uint public totalStaked;

    uint public stakingTaxRate;                     

    uint public registrationTax;

    uint8 public dailyROI;                         

    uint public unstakingTaxRate;                   

    uint public minimumStakeValue;

    uint public referralTaxAllocation;

    uint index;

    bool active = true;

    mapping(uint => address) public userIndex;

    mapping(address => uint) public stakes;

    mapping(address => uint) public stakeRewards;

    mapping(address => uint) public referralCount;

    mapping(address => uint) public referralRewards;

    mapping(address => uint) public lastClock;

    mapping(address => bool) public registered;


    event OnWithdrawal(address sender, uint amount);
    event OnStake(address sender, uint amount, uint tax);
    event OnUnstake(address sender, uint amount, uint tax);
    event OnDeposit(address sender, uint amount, uint time);
    event OnRegisterAndStake(address stakeholder, uint amount, uint totalTax , address _referrer);


    constructor(
        address _token,
        uint8 _stakingTaxRate, 
        uint8 _unstakingTaxRate,
        uint8 _dailyROI,
        uint _registrationTax,
        uint _referralTaxAllocation,
        uint _minimumStakeValue) public {


        lead = _token;
        stakingTaxRate = _stakingTaxRate;
        unstakingTaxRate = _unstakingTaxRate;
        dailyROI = _dailyROI;
        registrationTax = _registrationTax;
        referralTaxAllocation = _referralTaxAllocation;
        minimumStakeValue = _minimumStakeValue;
    }


    modifier onlyRegistered() {
        require(registered[msg.sender] == true, "Staker must be registered");
        _;
    }


    modifier onlyUnregistered() {
        require(registered[msg.sender] == false, "Staker is already registered");
        _;
    }


    modifier whenActive() {
        require(active == true, "Smart contract is curently inactive");
        _;
    }


    function registerAndStake(uint _amount, address _referrer) external onlyUnregistered() whenActive() {

        require(msg.sender != _referrer, "Cannot refer self");

        require(registered[_referrer] || address(0x0) == _referrer, "Referrer must be registered");

        require(IERC20(lead).balanceOf(msg.sender) >= _amount, "Must have enough balance to stake");

        require(IERC20(lead).transferFrom(msg.sender, address(this), _amount), "Stake failed due to failed amount transfer.");

        require(_amount >= registrationTax.add(minimumStakeValue), "Must send at least enough LEAD to pay registration fee.");

        uint referralBonus = (registrationTax.mul(referralTaxAllocation)).div(100);

        uint finalAmount = _amount.sub(registrationTax);

        uint stakingTax = (stakingTaxRate.mul(finalAmount)).div(1000);

        if(_referrer != address(0x0)) {

            referralCount[_referrer]++;

            referralRewards[_referrer] = referralRewards[_referrer].add(referralBonus);
        } 

        stakes[msg.sender] = stakes[msg.sender].add(finalAmount).sub(stakingTax);

        totalStaked = totalStaked.add(finalAmount).sub(stakingTax);

        registered[msg.sender] = true;
        userIndex[index] = msg.sender;
        index++;

        lastClock[msg.sender] = now;

        emit OnRegisterAndStake(msg.sender, _amount, registrationTax.add(stakingTax), _referrer);
    }


    function calculateEarnings(address _stakeholder) public view returns(uint) {

        uint activeDays = (now.sub(lastClock[_stakeholder])).div(86400);

        return (stakes[_stakeholder].mul(dailyROI).mul(activeDays)).div(10000);
    }


    function stake(uint _amount) external onlyRegistered() whenActive() {

        require(_amount >= minimumStakeValue, "Amount is below minimum stake value.");

        require(IERC20(lead).balanceOf(msg.sender) >= _amount, "Must have enough balance to stake");

        require(IERC20(lead).transferFrom(msg.sender, address(this), _amount), "Stake failed due to failed amount transfer.");

        uint stakingTax = (stakingTaxRate.mul(_amount)).div(1000);

        uint afterTax = _amount.sub(stakingTax);

        totalStaked = totalStaked.add(afterTax);

        stakeRewards[msg.sender] = stakeRewards[msg.sender].add(calculateEarnings(msg.sender));

        uint remainder = (now.sub(lastClock[msg.sender])).mod(86400);

        lastClock[msg.sender] = now.sub(remainder);

        stakes[msg.sender] = stakes[msg.sender].add(afterTax);

        emit OnStake(msg.sender, afterTax, stakingTax);
    }



    function unstake(uint _amount) external onlyRegistered() {

        require(_amount <= stakes[msg.sender] && _amount > 0, 'Insufficient balance to unstake');

        uint unstakingTax = (unstakingTaxRate.mul(_amount)).div(1000);

        uint afterTax = _amount.sub(unstakingTax);

        uint unstakePlusAllEarnings = stakeRewards[msg.sender].add(referralRewards[msg.sender]).add(afterTax).add(calculateEarnings(msg.sender));

        IERC20(lead).transfer(msg.sender, unstakePlusAllEarnings);

        stakes[msg.sender] = stakes[msg.sender].sub(_amount);

        stakeRewards[msg.sender] = 0;

        referralRewards[msg.sender] = 0;

        referralCount[msg.sender] = 0;

        uint remainder = (now.sub(lastClock[msg.sender])).mod(86400);

        lastClock[msg.sender] = now.sub(remainder);

        totalStaked = totalStaked.sub(_amount);

        if(stakes[msg.sender] == 0) {

            _removeStakeholder(msg.sender);
        }

        emit OnUnstake(msg.sender, _amount, unstakingTax);
    }


    function isStakeholder(address _address) public view returns(bool, uint) {

        for (uint i = 0; i < index; i += 1){

            if (_address == userIndex[i]) {

                return (true, i);
            }
        }

        return (false, 0);
    }


    function _removeStakeholder(address _stakeholder) internal {

        registered[msg.sender] = false;

        (bool _isStakeholder, uint i) = isStakeholder(_stakeholder);
        if(_isStakeholder){
            delete userIndex[i];
        }
    }


    function withdrawEarnings() external onlyRegistered() whenActive() {

        uint totalReward = referralRewards[msg.sender].add(stakeRewards[msg.sender]).add(calculateEarnings(msg.sender));

        require(totalReward > 0, 'No reward to withdraw'); 

        IERC20(lead).transfer(msg.sender, totalReward);

        stakeRewards[msg.sender] = 0;

        referralRewards[msg.sender] = 0;

        referralCount[msg.sender] = 0;

        uint remainder = (now.sub(lastClock[msg.sender])).mod(86400);

        lastClock[msg.sender] = now.sub(remainder);

        emit OnWithdrawal(msg.sender, totalReward);
    }

    function changeActiveStatus() external onlyOwner() {
        if(active = true) {
            active == false;
        } else {
            active == true;
        }
    }


    function setStakingTaxRate(uint8 _stakingTaxRate) external onlyOwner() {
        stakingTaxRate = _stakingTaxRate;
    }


    function setUnstakingTaxRate(uint8 _unstakingTaxRate) external onlyOwner() {
        unstakingTaxRate = _unstakingTaxRate;
    }


    function setDailyROI(uint8 _dailyROI) external onlyOwner() {
        for(uint i = 0; i < index; i++){

            stakeRewards[userIndex[i]] = stakeRewards[userIndex[i]].add(calculateEarnings(userIndex[i]));

            uint remainder = (now.sub(lastClock[userIndex[i]])).mod(86400);

            lastClock[userIndex[i]] = now.sub(remainder);
        }
        dailyROI = _dailyROI;
    }


    function setRegistrationTax(uint _registrationTax) external onlyOwner() {
        registrationTax = _registrationTax;
    }


    function setReferralTaxAllocation(uint _referralTaxAllocation) external onlyOwner() {
        referralTaxAllocation = _referralTaxAllocation;
    }


    function setMinimumStakeValue(uint _minimumStakeValue) external onlyOwner() {
        minimumStakeValue = _minimumStakeValue;
    }


    function adminWithdraw(address _address, uint _amount) external onlyOwner {

        require(IERC20(lead).balanceOf(address(this)) >= _amount, 'Insufficient LEAD balance in smart contract');

        IERC20(lead).transfer(_address, _amount);

        emit OnWithdrawal(_address, _amount);
    }


    function supplyPool() external onlyOwner() {

        uint totalClaimable;

        for(uint i = 0; i < index; i++){

            totalClaimable = stakeRewards[userIndex[i]].add(referralRewards[userIndex[i]]).add(stakes[userIndex[i]]).add(calculateEarnings(userIndex[i]));
        }

        require(totalClaimable > IERC20(lead).balanceOf(address(this)), 'Still have enough pool reserve');

        uint difference = totalClaimable.sub(IERC20(lead).balanceOf(address(this)));

        require(IERC20(lead).balanceOf(msg.sender) >= difference, 'Insufficient LEAD balance in owner wallet');

        IERC20(lead).transferFrom(msg.sender, address(this), difference);

        emit OnDeposit(msg.sender, difference, now);
    }
}

pragma solidity ^0.6.0;
pragma experimental ABIEncoderV2;

import "@openzeppelin/contracts/utils/SafeCast.sol";
import "@openzeppelin/contracts/token/ERC20/ERC20Burnable.sol";
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "./IPool.sol";
import "../utils/Timed.sol";
import "../utils/SafeMath128.sol";
import "../external/SafeMathCopy.sol";
import "../external/Decimal.sol";



abstract contract Pool is IPool, ERC20, ERC20Burnable, Timed {
	using Decimal for Decimal.D256;
	using SafeMath128 for uint128;
	using SafeCast for uint;

	bool internal initialized;

	IERC20 public override rewardToken;
	IERC20 public override stakedToken;

	uint128 public override claimedRewards;
	uint128 public override totalStaked;

    mapping (address => uint) public override stakedBalance;





	constructor(
		uint32 _duration,
		string memory _name,
		string memory _ticker
	) public ERC20(_name, _ticker) Timed(_duration) {}

	function claim(address from, address to) external override returns(uint amountReward) {
		amountReward = _claim(from, to);
		emit Claim(from, to, amountReward);
		return amountReward;
	}

	function deposit(address to, uint amount) external override {
		address from = msg.sender;
		_deposit(from, to, amount);
		emit Deposit(from, to, amount);
	}

	function withdraw(address to) external override returns(uint amountStaked, uint amountReward) {
		address from = msg.sender;
		amountReward = _claim(from, to);
		amountStaked = _withdraw(from, to);
		emit Withdraw(from, to, amountStaked, amountReward);
		return (amountStaked, amountReward);
	}

	function init() public override virtual {
		require(!initialized, "Pool: Already initialized");
		_initTimed();
		initialized = true;
	}

    function redeemableReward(address account) public view override returns(uint amountReward, uint amountPool) {
		amountPool = _redeemablePoolTokens(account);
		return (releasedReward() * amountPool / _totalRedeemablePoolTokens(), amountPool);
    }

	function releasedReward() public view override returns (uint) {
		uint total = rewardBalance();
		uint unreleased = unreleasedReward();
		require(total >= unreleased, "Pool: Released Reward underflow");
		return total - unreleased;
	}

	function unreleasedReward() public view override returns (uint) {
		if (isTimeEnded()) {
			return 0;
		}
		return _unreleasedReward(totalReward(), uint(duration), uint(timestamp()));
	}

	function totalReward() public view override returns (uint) {
		return rewardBalance() + uint(claimedRewards);
	}

	function rewardBalance() public view override returns (uint) {
		return rewardToken.balanceOf(address(this));
	}

	function burnFrom(address account, uint amount) public override {
		if (msg.sender == account) {
			increaseAllowance(account, amount);
		}
		super.burnFrom(account, amount);
	}

	function _totalRedeemablePoolTokens() internal view returns(uint) {
		uint total = totalSupply();
		uint balance = _twfb(uint(totalStaked));
		require(total >= balance, "Pool: Total redeemable underflow");
		return total - balance;
	}

	function _redeemablePoolTokens(address account) internal view returns(uint) {
		uint total = balanceOf(account);
		uint balance = _twfb(stakedBalance[account]);
		require(total >= balance, "Pool: Redeemable underflow");
		return total - balance;
	}

	function _unreleasedReward(uint _totalReward, uint _duration, uint _time) internal view virtual returns (uint);

	function _deposit(address from, address to, uint amount) internal {
		require(initialized, "Pool: Uninitialized");
		require(amount <= stakedToken.balanceOf(from), "Pool: Balance too low to stake");

		stakedToken.transferFrom(from, address(this), amount);

		stakedBalance[to] += amount;
		_incrementStaked(amount);

		uint poolTokens = _twfb(amount);
		require(poolTokens != 0, "Pool: Window has ended");

		_mint(to, poolTokens);
	}

	function _withdraw(address from, address to) internal returns(uint amountStaked) {
		amountStaked = stakedBalance[from];
		stakedBalance[from] = 0;
		stakedToken.transfer(to, amountStaked);

		uint amountPool = balanceOf(from);
		if (amountPool != 0) {
			_burn(from, amountPool);
		}
		return amountStaked;	
	}

	function _claim(address from, address to) internal returns(uint) {
		(uint amountReward, uint amountPool) = redeemableReward(from);
		require(amountPool != 0, "Pool: User has no redeemable pool tokens");

		burnFrom(from, amountPool);
		_incrementClaimed(amountReward);

		rewardToken.transfer(to, amountReward);
		return amountReward;
	}

	function _incrementClaimed(uint amount) internal {
		claimedRewards = claimedRewards.add(amount.toUint128());
	}

	function _incrementStaked(uint amount) internal {
		totalStaked = totalStaked.add(amount.toUint128());
	}

	function _twfb(uint amount) internal view returns(uint) {
		return amount * uint(remainingTime());
	}


	function _beforeTokenTransfer(address from, address to, uint amount) internal override {
        if (from != address(0) && to != address(0)) {
 			Decimal.D256 memory ratio = Decimal.ratio(amount, balanceOf(from));
 			uint amountStaked = ratio.mul(stakedBalance[from]).asUint256();

 			stakedBalance[from] -= amountStaked;
 			stakedBalance[to] += amountStaked;
        }
    }

	function _setTokens(address _rewardToken, address _stakedToken) internal {
		rewardToken = IERC20(_rewardToken);
		stakedToken = IERC20(_stakedToken);	
	}
}

pragma solidity ^0.6.2;

abstract contract Context {
    function _msgSender() internal view virtual returns (address) {
        return msg.sender;
    }

    function _msgData() internal view virtual returns (bytes calldata) {
        this; 
        return msg.data;
    }
}

contract Ownable is Context {
    address private _owner;
    uint256 private _unlockTime;
    address private _previousOwner;

    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);


    constructor () public {
        address msgSender = _msgSender();
        _owner = msgSender;
        emit OwnershipTransferred(address(0), msgSender);
    }


    function owner() public view returns (address) {
        return _owner;
    }


    modifier onlyOwner() {
        require(_owner == _msgSender(), "Ownable: caller is not the owner");
        _;
    }


    function renounceOwnership() public virtual onlyOwner {
        emit OwnershipTransferred(_owner, address(0));
        _owner = address(0);
    }

    function previousOwner() public view returns(address) {
        return _previousOwner;
    }

    function getUnlockTime() public view returns(uint256){
        return _unlockTime;
    }


    function transferOwnership(address newOwner, uint256 unlockTime) public virtual onlyOwner {
        require(newOwner != address(0), "Ownable: new owner is the zero address");
        _previousOwner = _owner;
        _unlockTime = unlockTime;
        emit OwnershipTransferred(_owner, newOwner);
        _owner = newOwner;
    }
}

